import React, { useState } from 'react';
import { Tab, ScheduleEvent, Expense } from './types';
import { MOCK_EVENTS, MOCK_EXPENSES } from './constants';
import { ScheduleView } from './components/ScheduleView';
import { ExpenseView } from './components/ExpenseView';
import { PlanningView } from './components/PlanningView';
import { JournalView } from './components/JournalView';
import { Calendar, DollarSign, BookOpen, CheckSquare } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.SCHEDULE);

  // App-level state (In a real app, this would be Redux or Context + Firebase Hooks)
  const [events] = useState<ScheduleEvent[]>(MOCK_EVENTS);
  const [expenses, setExpenses] = useState<Expense[]>(MOCK_EXPENSES);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: Date.now().toString(),
    };
    setExpenses([expense, ...expenses]);
  };

  const renderContent = () => {
    switch (activeTab) {
      case Tab.SCHEDULE:
        return <ScheduleView events={events} />;
      case Tab.EXPENSE:
        return <ExpenseView expenses={expenses} onAddExpense={handleAddExpense} />;
      case Tab.PLANNING:
        return <PlanningView />;
      case Tab.JOURNAL:
        return <JournalView />;
      default:
        return <ScheduleView events={events} />;
    }
  };

  return (
    <div className="h-screen w-full max-w-md mx-auto bg-paper flex flex-col relative shadow-2xl overflow-hidden">
      {/* Header */}
      <header className="px-6 py-5 flex justify-between items-center bg-paper z-10">
        <div>
           <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Korea Trip 🇰🇷</h1>
           <p className="text-xs text-slate-500 font-medium">Dec 20 - Dec 25, 2023</p>
        </div>
        <div className="w-10 h-10 rounded-full bg-white shadow-soft flex items-center justify-center border-2 border-slate-100 overflow-hidden">
           <img src="https://picsum.photos/100?random=99" alt="User" className="w-full h-full object-cover" />
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="absolute bottom-6 left-4 right-4 bg-white/90 backdrop-blur-md rounded-full shadow-[0px_8px_32px_rgba(0,0,0,0.1)] p-2 flex justify-between items-center z-50 border border-white/50">
        <NavButton 
          active={activeTab === Tab.SCHEDULE} 
          onClick={() => setActiveTab(Tab.SCHEDULE)} 
          icon={Calendar} 
          label="Plan" 
        />
        <NavButton 
          active={activeTab === Tab.EXPENSE} 
          onClick={() => setActiveTab(Tab.EXPENSE)} 
          icon={DollarSign} 
          label="Money" 
        />
        <NavButton 
          active={activeTab === Tab.JOURNAL} 
          onClick={() => setActiveTab(Tab.JOURNAL)} 
          icon={BookOpen} 
          label="Journal" 
        />
        <NavButton 
          active={activeTab === Tab.PLANNING} 
          onClick={() => setActiveTab(Tab.PLANNING)} 
          icon={CheckSquare} 
          label="Lists" 
        />
      </nav>
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.FC<{ size?: number; className?: string }>;
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon: Icon, label }) => (
  <button
    onClick={onClick}
    className={`flex flex-col items-center justify-center w-16 h-16 rounded-full transition-all duration-300 ${
      active 
        ? 'bg-winter-500 text-white shadow-lg -translate-y-4 scale-110' 
        : 'text-slate-400 hover:text-slate-600 active:scale-95'
    }`}
  >
    <Icon size={24} className={active ? 'animate-bounce-short' : ''} />
    {!active && <span className="text-[10px] font-bold mt-1">{label}</span>}
  </button>
);

export default App;

