             const dateStr = dateObj.toLocaleDateString() + ' ' + dateObj.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});

             return (
               <div key={entry.id} className="bg-white p-4 rounded-tr-3xl rounded-bl-3xl rounded-br-3xl shadow-sm border border-slate-100">
