    { display: '31 Sat', val: '2026-01-31' },
    { display: '01 Sun', val: '2026-02-01' },
    { display: '02 Mon', val: '2026-02-02' },
    { display: '03 Tue', val: '2026-02-03' },
    { display: '04 Wed', val: '2026-02-04' },
    { display: '05 Thu', val: '2026-02-05' },
  ];

  const [selectedDate, setSelectedDate] = useState(dates[0].val);
  const [events, setEvents] = useState<ScheduleEvent[]>([]);
