  const [newCategory, setNewCategory] = useState<EventCategory>(EventCategory.SIGHTSEEING);
  const [newNotes, setNewNotes] = useState('');

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'events'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedEvents: ScheduleEvent[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as ScheduleEvent));
      setEvents(fetchedEvents);
    });
    return () => unsubscribe();
  }, []);

  const handleAddEvent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTitle) return;

    try {
      await addDoc(collection(db, 'events'), {
        date: selectedDate,
        time: '', // Field kept for compatibility but empty
        title: newTitle,
        location: newLocation,
        category: newCategory,
        notes: newNotes,
        createdAt: new Date().toISOString()
      });
      setIsAdding(false);
      setNewTitle('');
      setNewLocation('');
      setNewNotes('');
    } catch (error) {
      console.error("Error adding event: ", error);
    }
  };

  const handleDeleteEvent = async (id: string) => {
    if(window.confirm("Remove this plan?")) {
      await deleteDoc(doc(db, 'events', id));
    }
  }

  const filteredEvents = events
    .filter(e => e.date === selectedDate)
    // Sort by created time since we don't have explicit event time anymore, or keep roughly
    .sort((a, b) => (a.notes || '').localeCompare(b.notes || '')); 

  if (isAdding) {
     return (
        <div className="h-full p-4 overflow-y-auto pb-24">
           <div className="bg-white rounded-3xl p-6 shadow-soft border-2 border-slate-100 relative">
              <button onClick={() => setIsAdding(false)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
              <h2 className="text-xl font-bold text-slate-800 mb-6">New Plan</h2>
              <form onSubmit={handleAddEvent} className="space-y-4">
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">What</label>
                    <input type="text" placeholder="Activity Name" value={newTitle} onChange={e => setNewTitle(e.target.value)} className="w-full mt-1 p-3 bg-slate-50 rounded-xl border border-slate-200" required />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">Where</label>
                    <input type="text" placeholder="Location" value={newLocation} onChange={e => setNewLocation(e.target.value)} className="w-full mt-1 p-3 bg-slate-50 rounded-xl border border-slate-200" />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">Category</label>
                    <div className="grid grid-cols-3 gap-2 mt-1">
                       {Object.values(EventCategory).map(cat => (
                          <button
                            key={cat}
                            type="button"
                            onClick={() => setNewCategory(cat)}
                            className={`px-2 py-3 rounded-xl text-xs font-bold transition-all flex flex-col items-center gap-1 ${newCategory === cat ? CATEGORY_COLORS[cat] + ' ring-2 ring-offset-1 ring-slate-200' : 'bg-slate-50 text-slate-500 border border-slate-100'}`}
                          >
                             <span className="text-xl">{CATEGORY_ICONS[cat]}</span>
                             {cat}
                          </button>
                       ))}
                    </div>
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">Notes</label>
                    <textarea placeholder="Details..." value={newNotes} onChange={e => setNewNotes(e.target.value)} className="w-full mt-1 p-3 bg-slate-50 rounded-xl border border-slate-200 h-20" />
                 </div>
                 <button type="submit" className="w-full py-3 bg-winter-500 text-white font-bold rounded-xl shadow-soft-sm active:scale-95 transition-transform">
                    Add to Schedule
                 </button>
              </form>
           </div>
        </div>
     )
  }

  return (
    <div className="h-full flex flex-col relative">
      {/* Date Picker */}
      <div className="flex overflow-x-auto no-scrollbar gap-3 p-4 pb-2 sticky top-0 bg-paper/95 backdrop-blur z-10">
        {dates.map((d) => (
          <button
            key={d.val}
            onClick={() => setSelectedDate(d.val)}
            className={`flex-shrink-0 flex flex-col items-center justify-center w-16 h-20 rounded-2xl border-2 transition-all active:scale-95 duration-200 ${
              selectedDate === d.val
                ? 'bg-winter-200 border-winter-400 shadow-soft text-winter-900'
                : 'bg-white border-slate-200 text-slate-400'
            }`}
          >
            <span className="text-sm font-bold">{d.display.split(' ')[0]}</span>
            <span className="text-xs">{d.display.split(' ')[1]}</span>
          </button>
        ))}
      </div>

      {/* Timeline */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-24">
        {filteredEvents.length === 0 ? (
          <div className="text-center text-slate-400 mt-10">
            <p>No plans yet for this day.</p>
            <button onClick={() => setIsAdding(true)} className="mt-4 text-winter-600 font-bold hover:underline">Add something?</button>
          </div>
        ) : (
          filteredEvents.map((event, index) => (
            <div key={event.id} className="relative pl-6 group">
              {/* Timeline Line */}
              {index !== filteredEvents.length - 1 && (
                <div className="absolute left-[11px] top-8 bottom-[-16px] w-[2px] bg-slate-200"></div>
              )}
              {/* Dot - Now an Icon */}
              <div className={`absolute left-[-8px] top-3 w-10 h-10 rounded-full border-4 border-white shadow-sm z-10 flex items-center justify-center text-lg bg-white`}>
                {CATEGORY_ICONS[event.category]}
              </div>

              {/* Card */}
              <div className={`relative p-4 ml-2 rounded-2xl border-2 shadow-soft-sm bg-white hover:shadow-soft transition-all active:scale-[0.98] ${CATEGORY_COLORS[event.category].split(' ')[2]}`}>
                <button onClick={() => handleDeleteEvent(event.id)} className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 text-slate-400 hover:text-rose-500 transition-opacity p-1"><X size={14}/></button>
                <div className="flex justify-between items-start mb-1">
                  <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider mb-2 ${CATEGORY_COLORS[event.category]}`}>
                    {event.category}
                  </div>
                </div>

                <h3 className="text-lg font-bold text-slate-800 mb-1 leading-tight">{event.title}</h3>

                {event.location && (
                    <div className="flex items-center text-slate-600 text-sm mb-2">
                    <MapPin size={14} className="mr-1 text-winter-500" />
                    {event.location}
                    </div>
                )}

                {event.notes && (
                  <div className="mt-2 text-xs text-slate-500 bg-slate-50 p-2 rounded-lg border border-slate-100 flex items-start">
                    <Info size={12} className="mr-1 mt-0.5 flex-shrink-0" />
                    {event.notes}
                  </div>
                )}

                {event.mapLink && (
                  <a href={event.mapLink} target="_blank" rel="noreferrer" className="block mt-3 text-center text-xs font-bold text-winter-600 bg-winter-50 py-2 rounded-xl hover:bg-winter-100 transition-colors">
                    Open Map
                  </a>
                )}
              </div>
            </div>
          ))
        )}
      </div>

      {/* Floating Add Button */}
      {!isAdding && (
         <button 
           onClick={() => setIsAdding(true)}
           className="absolute bottom-24 right-4 w-14 h-14 bg-winter-500 text-white rounded-full shadow-soft flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-20"
         >
            <Plus size={28} />
         </button>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Expense, Member, EventCategory } from '../types';
import { EXCHANGE_RATE, CATEGORY_ICONS, CATEGORY_COLORS } from '../constants';
import { Plus, Wallet, Users } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, query, onSnapshot, addDoc, orderBy } from 'firebase/firestore';

interface ExpenseViewProps {
  members: Member[];
}

export const ExpenseView: React.FC<ExpenseViewProps> = ({ members }) => {
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [isAdding, setIsAdding] = useState(false);

  // Form State
  const [newAmount, setNewAmount] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState<string>('Food');
  const [payer, setPayer] = useState(members[0]?.id || '');
  const [selectedSplits, setSelectedSplits] = useState<string[]>([]);

  // Initialize splits when members load
  useEffect(() => {
    if (members.length > 0 && selectedSplits.length === 0) {
        setSelectedSplits(members.map(m => m.id));
        if (!payer) setPayer(members[0].id);
    }
  }, [members]);

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'expenses'), orderBy('date', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedExpenses: Expense[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as Expense));
      setExpenses(fetchedExpenses);
    });
    return () => unsubscribe();
  }, []);

  const totalKRW = expenses.reduce((acc, curr) => acc + curr.amountKRW, 0);
  const totalTWD = expenses.reduce((acc, curr) => acc + curr.amountTWD, 0);

  const handleAdd = async () => {
    if (!newAmount || !description) return;
    const amountKRW = parseInt(newAmount);

    try {
      await addDoc(collection(db, 'expenses'), {
        amountKRW,
        amountTWD: Math.round(amountKRW * EXCHANGE_RATE),
        category,
        description,
        payerId: payer,
        splitWithIds: selectedSplits,
        date: new Date().toISOString().split('T')[0],
        timestamp: new Date().toISOString()
      });
      setIsAdding(false);
      setNewAmount('');
      setDescription('');
    } catch (error) {
      console.error("Error adding expense: ", error);
    }
  };

  const toggleSplit = (id: string) => {
    if (selectedSplits.includes(id)) {
      setSelectedSplits(selectedSplits.filter(s => s !== id));
    } else {
      setSelectedSplits([...selectedSplits, id]);
    }
  };

  if (isAdding) {
    return (
      <div className="p-4 h-full overflow-y-auto pb-24">
        <div className="bg-white rounded-3xl p-6 shadow-soft border-2 border-slate-100">
          <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center">
            <Plus className="mr-2 text-winter-500" /> New Expense
          </h2>

          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Amount (KRW)</label>
              <input
                type="number"
                inputMode="numeric"
                value={newAmount}
                onChange={(e) => setNewAmount(e.target.value)}
                className="w-full text-3xl font-bold text-slate-800 border-b-2 border-slate-200 focus:border-winter-400 outline-none py-2 bg-transparent placeholder-slate-200"
                placeholder="0"
              />
              <div className="text-right text-sm text-slate-400 mt-1">
                ≈ {Math.round((parseInt(newAmount) || 0) * EXCHANGE_RATE)} TWD
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">For What?</label>
              <input
                type="text"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full p-3 bg-slate-50 rounded-xl border border-slate-200 focus:border-winter-400 outline-none text-slate-700"
                placeholder="e.g., Dinner, Taxi..."
              />
            </div>

            <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Category</label>
                <div className="flex gap-2 overflow-x-auto no-scrollbar">
                    {Object.values(EventCategory).map(cat => (
                        <button
                            key={cat}
                            onClick={() => setCategory(cat)}
                            className={`flex-shrink-0 px-3 py-2 rounded-xl text-xs font-bold border transition-all ${category === cat ? 'bg-winter-50 border-winter-400 text-winter-700' : 'border-slate-100 text-slate-500'}`}
                        >
                            <span className="mr-1">{CATEGORY_ICONS[cat]}</span> {cat}
                        </button>
                    ))}
                </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Who Paid?</label>
              <div className="flex gap-2 overflow-x-auto no-scrollbar py-1">
                {members.map(m => (
                  <button
                    key={m.id}
                    onClick={() => setPayer(m.id)}
                    className={`flex-shrink-0 flex items-center gap-2 px-3 py-2 rounded-full border transition-all ${payer === m.id ? 'bg-slate-800 text-white border-slate-800 shadow-md' : 'bg-white border-slate-200 text-slate-600'}`}
                  >
                    <img src={m.avatar} alt={m.name} className="w-6 h-6 rounded-full" />
                    <span className="text-sm font-medium">{m.name}</span>
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Split With</label>
              <div className="grid grid-cols-5 gap-2">
                {members.map(m => (
                  <button
                    key={m.id}
                    onClick={() => toggleSplit(m.id)}
                    className={`flex flex-col items-center justify-center p-2 rounded-xl border-2 transition-all ${selectedSplits.includes(m.id) ? `border-winter-400 bg-winter-50` : 'border-transparent opacity-50 grayscale'}`}
                  >
                    <img src={m.avatar} alt={m.name} className="w-8 h-8 rounded-full mb-1" />
                    <span className="text-[10px] font-bold text-slate-600 truncate w-full text-center">{m.name}</span>
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="mt-8 flex gap-3">
            <button
              onClick={() => setIsAdding(false)}
              className="flex-1 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-100 transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleAdd}
              className="flex-1 py-3 rounded-xl font-bold bg-winter-500 text-white shadow-soft-sm active:translate-y-1 active:shadow-none transition-all"
            >
              Save
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col">
      {/* Dashboard */}
      <div className="p-4">
        <div className="bg-winter-800 text-white rounded-3xl p-6 shadow-soft relative overflow-hidden">
          <div className="absolute top-0 right-0 p-3 opacity-10">
            <Wallet size={120} />
          </div>
          <div className="relative z-10">
            <div className="text-winter-200 text-sm font-medium mb-1">Total Trip Expense</div>
            <div className="text-3xl font-bold mb-2">₩ {totalKRW.toLocaleString()}</div>
            <div className="inline-block bg-white/20 backdrop-blur px-3 py-1 rounded-full text-xs font-medium">
              ≈ NT$ {totalTWD.toLocaleString()}
            </div>
          </div>
        </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto px-4 pb-24 space-y-3">
        <div className="flex justify-between items-center mb-2">
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Recent Transactions</h3>
          <button onClick={() => setIsAdding(true)} className="text-winter-600 bg-winter-100 p-2 rounded-full hover:bg-winter-200 transition-colors">
            <Plus size={20} />
          </button>
        </div>

        {expenses.map(expense => {
          const payerMember = members.find(m => m.id === expense.payerId);
          // Try to match category string to enum to get icon, or fallback
          const icon = (CATEGORY_ICONS as any)[expense.category] || '💸';

          return (
            <div key={expense.id} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex justify-between items-center">
              <div className="flex items-center gap-3">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xl bg-slate-50 border border-slate-100`}>
                  {icon}
                </div>
                <div>
                  <div className="font-bold text-slate-800">{expense.description}</div>
                  <div className="text-xs text-slate-400 flex items-center gap-1">
                     <span className="font-medium text-slate-500">{payerMember?.name || 'Unknown'}</span> paid
                     <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                     <Users size={10} /> {expense.splitWithIds.length}
                  </div>
                </div>
              </div>
              <div className="text-right">
                <div className="font-bold text-slate-800">₩{expense.amountKRW.toLocaleString()}</div>
                <div className="text-[10px] text-slate-400">NT$ {expense.amountTWD.toLocaleString()}</div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { TodoItem, Member } from '../types';
import { Check, ShoppingBag, Briefcase, List, Plus } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, query, onSnapshot, addDoc, updateDoc, doc } from 'firebase/firestore';

interface PlanningViewProps {
  members: Member[];
}

export const PlanningView: React.FC<PlanningViewProps> = ({ members }) => {
  const [activeTab, setActiveTab] = useState<'todo' | 'packing' | 'shopping'>('packing');
  // Default to first member ID if available
  const [activeMemberId, setActiveMemberId] = useState<string>('');
  const [todos, setTodos] = useState<TodoItem[]>([]);
  const [newItemText, setNewItemText] = useState('');

  useEffect(() => {
    if (members.length > 0 && !activeMemberId) {
        setActiveMemberId(members[0].id);
    }
  }, [members]);

  const activeMember = members.find(m => m.id === activeMemberId);

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'todos'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedTodos: TodoItem[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as TodoItem));
      setTodos(fetchedTodos);
    });
    return () => unsubscribe();
  }, []);

  const filteredTodos = todos.filter(
    t => t.ownerId === activeMemberId && t.type === activeTab
  );

  const toggleTodo = async (id: string, currentStatus: boolean) => {
    const todoRef = doc(db, 'todos', id);
    await updateDoc(todoRef, {
      completed: !currentStatus
    });
  };

  const addItem = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemText.trim()) return;

    try {
      await addDoc(collection(db, 'todos'), {
        text: newItemText,
        completed: false,
        ownerId: activeMemberId,
        type: activeTab,
        createdAt: new Date().toISOString()
      });
      setNewItemText('');
    } catch (error) {
      console.error("Error adding todo: ", error);
    }
  };

  return (
    <div className="h-full flex flex-col">
      {/* Member Selector */}
      <div className="px-4 pt-4 pb-2">
         <div className="flex gap-2 overflow-x-auto no-scrollbar pb-2">
            {members.map(m => (
              <button
                key={m.id}
                onClick={() => setActiveMemberId(m.id)}
                className={`flex-shrink-0 relative transition-all duration-300 ${activeMemberId === m.id ? 'scale-110 z-10' : 'opacity-60 scale-90'}`}
              >
                <div className={`w-14 h-14 rounded-full p-1 border-2 ${activeMemberId === m.id ? 'border-winter-400' : 'border-transparent'}`}>
                  <img src={m.avatar} alt={m.name} className="w-full h-full rounded-full object-cover" />
                </div>
                {activeMemberId === m.id && (
                   <span className="absolute -bottom-2 left-1/2 transform -translate-x-1/2 bg-winter-500 text-white text-[10px] px-2 py-0.5 rounded-full font-bold shadow-sm whitespace-nowrap">
                     {m.name}
                   </span>
                )}
              </button>
            ))}
         </div>
      </div>

      {/* List Type Tabs */}
      <div className="flex px-4 mt-2 gap-2">
        {[
          { id: 'packing', label: 'Packing', icon: Briefcase },
          { id: 'shopping', label: 'Buy', icon: ShoppingBag },
          { id: 'todo', label: 'Tasks', icon: List },
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex-1 flex items-center justify-center py-2 rounded-xl text-sm font-bold transition-all ${
              activeTab === tab.id
                ? 'bg-white shadow-soft text-winter-600 border-2 border-slate-100'
                : 'bg-transparent text-slate-400 hover:bg-white/50'
            }`}
          >
            <tab.icon size={16} className="mr-2" />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Checkbox List */}
      <div className="flex-1 overflow-y-auto p-4 pb-24 space-y-3">
        <div className={`p-4 rounded-3xl min-h-[300px] border-2 border-slate-100 bg-white/80 shadow-inner-soft`}>
          <h3 className="text-lg font-bold text-slate-700 mb-4 flex items-center">
            <span className={`w-2 h-8 rounded-full mr-3 ${activeMember?.color}`}></span>
            {activeMember?.name}'s {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} List
          </h3>

          <form onSubmit={addItem} className="mb-4 relative">
             <input 
                type="text" 
                value={newItemText}
                onChange={(e) => setNewItemText(e.target.value)}
                placeholder="Add new item..." 
                className="w-full pl-4 pr-10 py-3 rounded-xl bg-paper border border-slate-200 focus:border-winter-400 outline-none"
             />
             <button type="submit" className="absolute right-2 top-2 p-1 bg-winter-500 text-white rounded-lg hover:bg-winter-600">
               <Plus size={20} />
             </button>
          </form>

          <div className="space-y-2">
            {filteredTodos.map(item => (
              <div 
                key={item.id} 
                onClick={() => toggleTodo(item.id, item.completed)}
                className={`flex items-center p-3 rounded-xl cursor-pointer transition-all active:scale-[0.98] ${
                  item.completed ? 'bg-slate-50 opacity-60' : 'bg-white shadow-sm border border-slate-100'
                }`}
              >
                <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center mr-3 transition-colors ${
                  item.completed ? 'bg-winter-400 border-winter-400' : 'border-slate-300'
                }`}>
                  {item.completed && <Check size={14} className="text-white" />}
                </div>
                <span className={`text-sm font-medium ${item.completed ? 'text-slate-400 line-through' : 'text-slate-700'}`}>
                  {item.text}
                </span>
              </div>
            ))}
            {filteredTodos.length === 0 && (
               <div className="text-center text-slate-300 py-8 italic text-sm">
                  Nothing here yet.
               </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { PenTool, Send } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, query, onSnapshot, addDoc, orderBy } from 'firebase/firestore';
import { JournalEntry } from '../types';
import { MEMBERS } from '../constants';

export const JournalView: React.FC = () => {
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [newContent, setNewContent] = useState('');

  // Hardcode current user to first member for demo (or could be selected)
  const currentUser = MEMBERS[0];

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'journal'), orderBy('date', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedEntries: JournalEntry[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as JournalEntry));
      setEntries(fetchedEntries);
    });
    return () => unsubscribe();
  }, []);

  const handlePost = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newContent.trim()) return;

    try {
      await addDoc(collection(db, 'journal'), {
        content: newContent,
        date: new Date().toISOString(),
        authorId: currentUser.id,
      });
      setNewContent('');
    } catch (error) {
      console.error("Error posting journal: ", error);
    }
  };

  return (
    <div className="h-full flex flex-col p-4 overflow-y-auto pb-24">
       <div className="bg-white rounded-3xl p-6 shadow-soft mb-6 text-center border-2 border-slate-100">
          <div className="w-16 h-16 bg-winter-100 rounded-full flex items-center justify-center mx-auto mb-3 text-winter-600">
             <PenTool size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-800">Trip Journal</h2>
          <p className="text-slate-400 text-sm">Write down your thoughts</p>
       </div>

       {/* Simple Input Area */}
       <form onSubmit={handlePost} className="mb-6 relative">
          <textarea
             value={newContent}
             onChange={e => setNewContent(e.target.value)}
             placeholder="What happened today?"
             className="w-full p-4 pr-12 rounded-2xl border-2 border-slate-100 focus:border-winter-300 outline-none resize-none shadow-sm text-sm min-h-[100px]"
          />
          <button type="submit" className="absolute bottom-3 right-3 p-2 bg-winter-500 text-white rounded-xl shadow-md hover:bg-winter-600 transition-colors">
             <Send size={16} />
          </button>
       </form>

       <div className="space-y-4">
          {entries.map(entry => {
             const author = MEMBERS.find(m => m.id === entry.authorId);
             const dateObj = new Date(entry.date);
             const dateStr = dateObj.toLocaleDateString() + ' ' + dateObj.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});

             return (
               <div key={entry.id} className="bg-white p-4 rounded-tr-3xl rounded-bl-3xl rounded-br-3xl shadow-sm border border-slate-100">
                  <div className="flex items-center gap-2 mb-2">
                     <img src={author?.avatar} alt={author?.name} className="w-6 h-6 rounded-full" />
                     <div className="text-xs font-bold text-slate-400">{dateStr}</div>
                  </div>
                  <p className="text-slate-600 leading-relaxed text-sm whitespace-pre-wrap">
                     {entry.content}
                  </p>
               </div>
             );
          })}

          {entries.length === 0 && (
             <div className="text-center text-slate-300 text-sm italic">
                No entries yet.
             </div>
          )}
       </div>
    </div>
  );
};

