  const [newCategory, setNewCategory] = useState<EventCategory>(EventCategory.SIGHTSEEING);
  const [newNotes, setNewNotes] = useState('');

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'events'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedEvents: ScheduleEvent[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as ScheduleEvent));
      setEvents(fetchedEvents);
    });
    return () => unsubscribe();
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setNewLocation('');
    setNewCategory(EventCategory.SIGHTSEEING);
    setNewNotes('');
    setIsModalOpen(true);
  };

  const openEditModal = (event: ScheduleEvent) => {
    setEditingId(event.id);
    setNewLocation(event.location);
    setNewCategory(event.category);
    setNewNotes(event.notes || '');
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newLocation) return;

    try {
      if (editingId) {
        // Update existing
        await updateDoc(doc(db, 'events', editingId), {
          location: newLocation,
          category: newCategory,
          notes: newNotes,
        });
      } else {
        // Add new
        await addDoc(collection(db, 'events'), {
          date: selectedDate,
          time: '', 
          title: '', 
          location: newLocation,
          category: newCategory,
          notes: newNotes,
          createdAt: new Date().toISOString()
        });
      }
      setIsModalOpen(false);
      setEditingId(null);
      setNewLocation('');
      setNewNotes('');
    } catch (error) {
      console.error("Error saving event: ", error);
    }
