            onClick={() => setSelectedDate(d.val)}
            className={`flex-shrink-0 flex flex-col items-center justify-center w-16 h-16 rounded-2xl border-2 transition-all active:scale-95 duration-200 ${
              selectedDate === d.val
                ? 'bg-winter-200 border-winter-400 shadow-soft text-winter-900'
                : 'bg-white border-slate-200 text-slate-400'
            }`}
          >
            <span className="text-xs font-bold whitespace-nowrap">{d.display.includes(' ') ? d.display.split(' ')[0] : d.display}</span>
            <span className="text-[10px]">{d.display.includes(' ') ? d.display.split(' ')[1] : ''}</span>
          </button>
        ))}
      </div>

      {/* Timeline */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-24">
        {filteredEvents.length === 0 ? (
          <div className="text-center text-slate-400 mt-10">
            <p>{selectedDate === 'PRE_TRIP' ? '沒有行前準備事項' : '這天還沒有安排行程'}</p>
            <button onClick={openAddModal} className="mt-4 text-winter-600 font-bold hover:underline">新增一個？</button>
          </div>
        ) : (
          filteredEvents.map((event, index) => (
            <div key={event.id} className="relative pl-6 group">
              {/* Timeline Line */}
              {index !== filteredEvents.length - 1 && (
                <div className="absolute left-[11px] top-8 bottom-[-16px] w-[2px] bg-slate-200"></div>
              )}
              {/* Dot - Now an Icon */}
              <div className={`absolute left-[-8px] top-3 w-10 h-10 rounded-full border-4 border-white shadow-sm z-10 flex items-center justify-center text-lg bg-white`}>
                {CATEGORY_ICONS[event.category]}
              </div>

              {/* Card - Click to Edit */}
              <div 
                onClick={() => openEditModal(event)}
                className={`relative p-4 ml-2 rounded-2xl border-2 shadow-soft-sm bg-white hover:shadow-soft transition-all active:scale-[0.98] cursor-pointer ${CATEGORY_COLORS[event.category].split(' ')[2]}`}
              >
                <button onClick={(e) => handleDeleteEvent(event.id, e)} className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 text-slate-400 hover:text-rose-500 transition-opacity p-2 z-20"><X size={14}/></button>

                <div className="flex justify-between items-start mb-1">
                  <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider mb-2 ${CATEGORY_COLORS[event.category]}`}>
                    {event.category}
                  </div>
                </div>

                <h3 className="text-lg font-bold text-slate-800 mb-1 leading-tight flex items-center">
                   <MapPin size={16} className="mr-1 text-winter-500 inline flex-shrink-0" />
                   {event.location}
                </h3>

                {event.notes && (
                  <div className="mt-2 text-xs text-slate-500 bg-slate-50 p-2 rounded-lg border border-slate-100 flex items-start">
                    <Info size={12} className="mr-1 mt-0.5 flex-shrink-0" />
                    {event.notes}
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>

      {/* Floating Add Button */}
      <button 
        onClick={openAddModal}
        className="absolute bottom-24 right-4 w-14 h-14 bg-winter-500 text-white rounded-full shadow-soft flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-20"
      >
        <Plus size={28} />
      </button>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <div className="absolute inset-0 z-50 bg-black/20 backdrop-blur-sm flex items-end sm:items-center justify-center p-4">
           <div className="bg-white w-full rounded-3xl p-6 shadow-2xl border-2 border-slate-100 relative animate-in slide-in-from-bottom-10 fade-in">
              <button onClick={() => setIsModalOpen(false)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
              <h2 className="text-xl font-bold text-slate-800 mb-6">{editingId ? '編輯行程' : '新增行程'}</h2>
              <form onSubmit={handleSubmit} className="space-y-4">
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">地點 / 事項</label>
                    <input type="text" placeholder={selectedDate === 'PRE_TRIP' ? "例如：買SIM卡、換錢..." : "例如：景福宮、弘大..."} value={newLocation} onChange={e => setNewLocation(e.target.value)} className="w-full mt-1 p-3 bg-slate-50 rounded-xl border border-slate-200 focus:border-winter-400 outline-none" required />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">分類</label>
                    <div className="grid grid-cols-5 gap-1 mt-1">
                       {Object.values(EventCategory).map(cat => (
                          <button
                            key={cat}
                            type="button"
                            onClick={() => setNewCategory(cat)}
                            className={`px-1 py-2 rounded-lg text-[10px] font-bold transition-all flex flex-col items-center gap-1 ${newCategory === cat ? CATEGORY_COLORS[cat] + ' ring-2 ring-offset-1 ring-slate-200' : 'bg-slate-50 text-slate-500 border border-slate-100'}`}
                          >
                             <span className="text-lg">{CATEGORY_ICONS[cat]}</span>
                             {cat}
                          </button>
                       ))}
                    </div>
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">備註</label>
