                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-xl font-bold text-slate-800">{editingId ? '編輯款項' : '新增記帳'}</h2>
                    {editingId && <button onClick={() => handleDelete(editingId)} className="text-xs text-rose-500 font-bold mr-8">刪除</button>}
