      await addDoc(collection(db, 'todos'), {
        text: newItemText,
        completed: false,
        ownerId: activeMemberId,
        type: activeTab,
        createdAt: new Date().toISOString()
      });
      setNewItemText('');
    } catch (error) {
      console.error("Error adding todo: ", error);
