    const q = query(collection(db, 'events'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedEvents: ScheduleEvent[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as ScheduleEvent));
      setEvents(fetchedEvents);
    });
    return () => unsubscribe();
  }, []);

  // Firestore Sync - Pre-trip Tasks
  useEffect(() => {
    const q = query(collection(db, 'pretrip_tasks'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedTasks: PreTripTask[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as PreTripTask));
      setPreTripTasks(fetchedTasks);
    });
    return () => unsubscribe();
  }, []);

  // --- Pre-trip Handlers ---
  const handleAddPreTripTask = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newTaskTitle.trim()) return;
      await addDoc(collection(db, 'pretrip_tasks'), {
          title: newTaskTitle,
          completedBy: [],
          createdAt: new Date().toISOString()
      });
      setNewTaskTitle('');
  };

  const deletePreTripTask = async (id: string) => {
      if(window.confirm("刪除此行前項目？")) {
          await deleteDoc(doc(db, 'pretrip_tasks', id));
      }
  }

  const toggleTaskCompletion = async (taskId: string, memberId: string, isCompleted: boolean) => {
      const taskRef = doc(db, 'pretrip_tasks', taskId);
      if (isCompleted) {
          await updateDoc(taskRef, { completedBy: arrayRemove(memberId) });
      } else {
          await updateDoc(taskRef, { completedBy: arrayUnion(memberId) });
      }
  };

  // --- Schedule Handlers ---
  const openAddModal = () => {
    setEditingId(null);
    setNewLocation('');
    setNewCategory(EventCategory.SIGHTSEEING);
    setNewNotes('');
    setIsModalOpen(true);
  };

  const openEditModal = (event: ScheduleEvent) => {
    setEditingId(event.id);
    setNewLocation(event.location);
    // Ensure the category is valid or default to Sightseeing
    setNewCategory(event.category as EventCategory || EventCategory.SIGHTSEEING);
    setNewNotes(event.notes || '');
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newLocation) return;

    try {
      if (editingId) {
        // Update existing
        await updateDoc(doc(db, 'events', editingId), {
          location: newLocation,
          category: newCategory,
          notes: newNotes,
        });
      } else {
        // Add new
        await addDoc(collection(db, 'events'), {
          date: selectedDate,
          time: '', 
          title: '', 
          location: newLocation,
          category: newCategory,
          notes: newNotes,
          createdAt: new Date().toISOString()
        });
      }
      setIsModalOpen(false);
      setEditingId(null);
      setNewLocation('');
      setNewNotes('');
    } catch (error) {
      console.error("Error saving event: ", error);
    }
  };

  const handleDeleteEvent = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent opening edit modal
    if(window.confirm("確定要刪除這個行程嗎？")) {
      await deleteDoc(doc(db, 'events', id));
      if (editingId === id) setIsModalOpen(false);
    }
  }

  const filteredEvents = events
    .filter(e => e.date === selectedDate)
    .sort((a, b) => (a.createdAt || '').localeCompare(b.createdAt || '')); 

  const sortedTasks = preTripTasks.sort((a, b) => (a.createdAt || '').localeCompare(b.createdAt || ''));

  return (
    <div className="h-full flex flex-col relative">
      {/* Date Picker */}
      <div className="flex overflow-x-auto no-scrollbar gap-2 p-4 pb-2 sticky top-0 bg-paper/95 backdrop-blur z-10">
        {dates.map((d) => (
          <button
            key={d.val}
            onClick={() => setSelectedDate(d.val)}
            className={`flex-shrink-0 flex flex-col items-center justify-center w-16 h-16 rounded-2xl border-2 transition-all active:scale-95 duration-200 ${
              selectedDate === d.val
                ? 'bg-winter-200 border-winter-400 shadow-soft text-winter-900'
                : 'bg-white border-slate-200 text-slate-400'
            }`}
          >
            <span className="text-xs font-bold whitespace-nowrap">{d.display.includes(' ') ? d.display.split(' ')[0] : d.display}</span>
            <span className="text-[10px]">{d.display.includes(' ') ? d.display.split(' ')[1] : ''}</span>
          </button>
        ))}
      </div>

      {/* Main Content */}
      <div className="flex-1 overflow-y-auto p-4 pb-24">

        {/* === PRE-TRIP CHECKLIST MODE === */}
        {selectedDate === 'PRE_TRIP' ? (
             <div className="space-y-4">
                 <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-soft-sm">
                     <h3 className="text-lg font-bold text-slate-800 mb-3">行前準備清單</h3>
                     <form onSubmit={handleAddPreTripTask} className="relative mb-6">
                        <input 
                           type="text" 
                           placeholder="新增準備事項 (例如: 買網卡...)" 
                           value={newTaskTitle}
                           onChange={e => setNewTaskTitle(e.target.value)}
                           className="w-full pl-4 pr-10 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:border-winter-400 outline-none text-sm"
                        />
                        <button type="submit" className="absolute right-2 top-2 p-1 bg-winter-500 text-white rounded-lg hover:bg-winter-600">
                           <Plus size={20} />
                        </button>
                     </form>

                     <div className="space-y-4">
                        {sortedTasks.map(task => (
                            <div key={task.id} className="bg-white rounded-xl border border-slate-100 p-3 shadow-sm">
                                <div className="flex justify-between items-start mb-2">
                                    <span className="font-bold text-slate-700">{task.title}</span>
                                    <button onClick={() => deletePreTripTask(task.id)} className="text-slate-300 hover:text-rose-400">
                                        <X size={14} />
                                    </button>
                                </div>
                                <div className="flex gap-3 mt-2 overflow-x-auto no-scrollbar">
                                    {members.map(member => {
                                        const isDone = task.completedBy.includes(member.id);
                                        return (
                                            <button 
                                                key={member.id}
                                                onClick={() => toggleTaskCompletion(task.id, member.id, isDone)}
                                                className={`flex flex-col items-center gap-1 transition-all active:scale-90`}
                                            >
                                                <div className={`w-8 h-8 rounded-full border-2 relative ${isDone ? 'border-winter-400' : 'border-slate-200 grayscale opacity-60'}`}>
                                                    <img src={member.avatar} className="w-full h-full rounded-full"/>
                                                    {isDone && (
                                                        <div className="absolute -bottom-1 -right-1 bg-winter-500 rounded-full p-0.5 border border-white">
                                                            <Check size={8} className="text-white"/>
                                                        </div>
                                                    )}
                                                </div>
                                                <span className={`text-[9px] font-bold ${isDone ? 'text-winter-600' : 'text-slate-400'}`}>
                                                    {member.name}
                                                </span>
                                            </button>
                                        )
                                    })}
                                </div>
                            </div>
                        ))}
                        {sortedTasks.length === 0 && (
                            <p className="text-center text-slate-400 text-sm py-4">還沒有項目，新增一個吧！</p>
                        )}
                     </div>
                 </div>
             </div>
        ) : (
        /* === TIMELINE MODE === */
        <>
            {filteredEvents.length === 0 ? (
            <div className="text-center text-slate-400 mt-10">
                <p>這天還沒有安排行程</p>
                <button onClick={openAddModal} className="mt-4 text-winter-600 font-bold hover:underline">新增一個？</button>
            </div>
            ) : (
            filteredEvents.map((event, index) => {
                const colorClass = CATEGORY_COLORS[event.category] || 'bg-slate-100 text-slate-700 border-slate-200';
                const borderColor = colorClass.split(' ')[2] || 'border-slate-200';
                const icon = CATEGORY_ICONS[event.category] || '📌';

                return (
                <div key={event.id} className="relative pl-6 group">
                    {/* Timeline Line */}
                    {index !== filteredEvents.length - 1 && (
                    <div className="absolute left-[11px] top-8 bottom-[-16px] w-[2px] bg-slate-200"></div>
                    )}
                    {/* Dot */}
                    <div className={`absolute left-[-8px] top-3 w-10 h-10 rounded-full border-4 border-white shadow-sm z-10 flex items-center justify-center text-lg bg-white`}>
                    {icon}
                    </div>

                    {/* Card */}
                    <div 
                    onClick={() => openEditModal(event)}
                    className={`relative p-4 ml-2 rounded-2xl border-2 shadow-soft-sm bg-white hover:shadow-soft transition-all active:scale-[0.98] cursor-pointer ${borderColor}`}
                    >
                    <button onClick={(e) => handleDeleteEvent(event.id, e)} className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 text-slate-400 hover:text-rose-500 transition-opacity p-2 z-20"><X size={14}/></button>

                    <div className="flex justify-between items-start mb-1">
                        <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider mb-2 ${colorClass}`}>
                        {event.category}
                        </div>
                    </div>

                    <h3 className="text-lg font-bold text-slate-800 mb-1 leading-tight flex items-center">
                        <MapPin size={16} className="mr-1 text-winter-500 inline flex-shrink-0" />
                        {event.location}
                    </h3>

                    {event.notes && (
                        <div className="mt-2 text-xs text-slate-500 bg-slate-50 p-2 rounded-lg border border-slate-100 flex items-start">
                        <Info size={12} className="mr-1 mt-0.5 flex-shrink-0" />
                        {event.notes}
                        </div>
                    )}
                    </div>
                </div>
                );
            })
            )}

            {/* Floating Add Button for Schedule */}
            <button 
                onClick={openAddModal}
                className="absolute bottom-24 right-4 w-14 h-14 bg-winter-500 text-white rounded-full shadow-soft flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-20"
            >
            <Plus size={28} />
            </button>
        </>
        )}
      </div>

      {/* Add/Edit Modal (Schedule Only) */}
      {isModalOpen && selectedDate !== 'PRE_TRIP' && (
        <div className="absolute inset-0 z-50 bg-black/20 backdrop-blur-sm flex items-end sm:items-center justify-center p-4">
           <div className="bg-white w-full rounded-3xl p-6 shadow-2xl border-2 border-slate-100 relative animate-in slide-in-from-bottom-10 fade-in">
              <button onClick={() => setIsModalOpen(false)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
              <h2 className="text-xl font-bold text-slate-800 mb-6">{editingId ? '編輯行程' : '新增行程'}</h2>
              <form onSubmit={handleSubmit} className="space-y-4">
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">地點 / 事項</label>
                    <input type="text" placeholder="例如：景福宮、弘大..." value={newLocation} onChange={e => setNewLocation(e.target.value)} className="w-full mt-1 p-3 bg-slate-50 rounded-xl border border-slate-200 focus:border-winter-400 outline-none" required />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">分類</label>
                    <div className="grid grid-cols-5 gap-1 mt-1">
                       {Object.values(EventCategory).map(cat => (
                          <button
                            key={cat}
                            type="button"
                            onClick={() => setNewCategory(cat)}
                            className={`px-1 py-2 rounded-lg text-[10px] font-bold transition-all flex flex-col items-center gap-1 ${newCategory === cat ? CATEGORY_COLORS[cat] + ' ring-2 ring-offset-1 ring-slate-200' : 'bg-slate-50 text-slate-500 border border-slate-100'}`}
                          >
                             <span className="text-lg">{CATEGORY_ICONS[cat]}</span>
                             {cat}
                          </button>
                       ))}
                    </div>
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">備註</label>
                    <textarea placeholder="詳細資訊..." value={newNotes} onChange={e => setNewNotes(e.target.value)} className="w-full mt-1 p-3 bg-slate-50 rounded-xl border border-slate-200 h-20 focus:border-winter-400 outline-none" />
                 </div>
                 <button type="submit" className="w-full py-3 bg-winter-500 text-white font-bold rounded-xl shadow-soft-sm active:scale-95 transition-transform">
                    {editingId ? '儲存變更' : '加入行程'}
                 </button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Expense, Member, EventCategory } from '../types';
import { EXCHANGE_RATE, CATEGORY_ICONS } from '../constants';
import { Plus, Users, Calendar, ArrowRightLeft, Calculator, X, ChevronRight } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, query, onSnapshot, addDoc, updateDoc, deleteDoc, doc, orderBy } from 'firebase/firestore';

interface ExpenseViewProps {
  members: Member[];
}

export const ExpenseView: React.FC<ExpenseViewProps> = ({ members }) => {
  const [activeSubTab, setActiveSubTab] = useState<'list' | 'settle'>('list');
  const [expenses, setExpenses] = useState<Expense[]>([]);

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [detailMemberId, setDetailMemberId] = useState<string | null>(null); // For personal spending details

  // Form State
  const [amountInput, setAmountInput] = useState('');
  const [inputCurrency, setInputCurrency] = useState<'KRW' | 'TWD'>('KRW');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState<string>(EventCategory.FOOD);
  const [payer, setPayer] = useState(members[0]?.id || '');
  const [selectedSplits, setSelectedSplits] = useState<string[]>([]);
  const [newDate, setNewDate] = useState(new Date().toISOString().split('T')[0]);

  // Initialize splits
  useEffect(() => {
    if (members.length > 0 && selectedSplits.length === 0) {
        setSelectedSplits(members.map(m => m.id));
        if (!payer) setPayer(members[0].id);
    }
  }, [members]);

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'expenses'), orderBy('date', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedExpenses: Expense[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as Expense));
      setExpenses(fetchedExpenses);
    });
    return () => unsubscribe();
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setAmountInput('');
    setInputCurrency('KRW');
    setDescription('');
    setCategory(EventCategory.FOOD);
    setNewDate(new Date().toISOString().split('T')[0]);
    // Reset splits to all
    setSelectedSplits(members.map(m => m.id));
    setPayer(members[0].id);
    setIsModalOpen(true);
  };

  const openEditModal = (exp: Expense) => {
    setEditingId(exp.id);
    // Use stored currency preference or default to KRW if not present
    const currency = exp.currency || 'KRW';
    setInputCurrency(currency);
    setAmountInput(currency === 'KRW' ? exp.amountKRW.toString() : exp.amountTWD.toString());
    setDescription(exp.description);
    setCategory(exp.category);
    setPayer(exp.payerId);
    setSelectedSplits(exp.splitWithIds);
    setNewDate(exp.date);
    setIsModalOpen(true);
  };

  const handleSave = async () => {
    if (!amountInput || !description) return;

    let amountKRW = 0;
    let amountTWD = 0;
    const inputVal = parseInt(amountInput);

    if (inputCurrency === 'KRW') {
        amountKRW = inputVal;
        amountTWD = Math.round(inputVal * EXCHANGE_RATE);
    } else {
        amountTWD = inputVal;
        amountKRW = Math.round(inputVal / EXCHANGE_RATE);
    }

    const expenseData = {
        amountKRW,
        amountTWD,
        currency: inputCurrency,
        category,
        description,
        payerId: payer,
        splitWithIds: selectedSplits,
        date: newDate,
        timestamp: new Date().toISOString()
    };

    try {
      if (editingId) {
        await updateDoc(doc(db, 'expenses', editingId), expenseData);
      } else {
        await addDoc(collection(db, 'expenses'), expenseData);
      }
      setIsModalOpen(false);
    } catch (error) {
      console.error("Error saving expense: ", error);
    }
  };

  const handleDelete = async (id: string) => {
      if (window.confirm("確定刪除這筆款項？")) {
          await deleteDoc(doc(db, 'expenses', id));
          setIsModalOpen(false);
      }
  }

  const toggleSplit = (id: string) => {
    if (selectedSplits.includes(id)) {
      if (selectedSplits.length > 1) { // Prevent empty split
        setSelectedSplits(selectedSplits.filter(s => s !== id));
      }
    } else {
      setSelectedSplits([...selectedSplits, id]);
    }
  };

  // --- SETTLEMENT LOGIC ---
  const calculateSettlement = () => {
    // 1. Calculate Net Balance for each person
    const balances: Record<string, number> = {};
    const paidTotals: Record<string, number> = {};
    const shareTotals: Record<string, number> = {};

    members.forEach(m => {
        balances[m.id] = 0;
        paidTotals[m.id] = 0;
        shareTotals[m.id] = 0;
    });

    expenses.forEach(exp => {
        const amount = exp.amountTWD; 

        // Credit the payer
        balances[exp.payerId] += amount;
        paidTotals[exp.payerId] += amount;

        // Debit the consumers
        const splitCount = exp.splitWithIds.length;
        if (splitCount > 0) {
            const share = amount / splitCount;
            exp.splitWithIds.forEach(id => {
                if (balances[id] !== undefined) {
                    balances[id] -= share;
                    shareTotals[id] += share;
                }
            });
        }
    });

    // 2. Simplification Algorithm (Who pays whom)
    const debtors: {id: string, amount: number}[] = [];
    const creditors: {id: string, amount: number}[] = [];

    Object.entries(balances).forEach(([id, amount]) => {
        if (amount < -1) debtors.push({ id, amount }); // Owe money
        else if (amount > 1) creditors.push({ id, amount }); // Are owed money
    });

    debtors.sort((a, b) => a.amount - b.amount); // Most negative first
    creditors.sort((a, b) => b.amount - a.amount); // Most positive first

    const transactions: {from: string, to: string, amount: number}[] = [];

    let i = 0; // debtor index
    let j = 0; // creditor index

    while (i < debtors.length && j < creditors.length) {
        const debtor = debtors[i];
        const creditor = creditors[j];

        // The amount to settle is the minimum of what debtor owes and creditor is owed
        const amount = Math.min(Math.abs(debtor.amount), creditor.amount);

        transactions.push({ from: debtor.id, to: creditor.id, amount: Math.round(amount) });

        debtor.amount += amount;
        creditor.amount -= amount;

        if (Math.abs(debtor.amount) < 1) i++;
        if (creditor.amount < 1) j++;
    }

    return { transactions, paidTotals, shareTotals };
  };

  const settlement = calculateSettlement();

  // Group expenses by date for List View
  const expensesByDate: Record<string, Expense[]> = {};
  expenses.forEach(exp => {
      if (!expensesByDate[exp.date]) {
          expensesByDate[exp.date] = [];
      }
      expensesByDate[exp.date].push(exp);
  });
  const sortedDates = Object.keys(expensesByDate).sort((a, b) => b.localeCompare(a));

  return (
    <div className="h-full flex flex-col">
      {/* Sub Tabs */}
      <div className="px-4 pt-4">
        <div className="bg-white p-1 rounded-xl border border-slate-100 flex shadow-sm">
            <button 
                onClick={() => setActiveSubTab('list')}
                className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeSubTab === 'list' ? 'bg-winter-100 text-winter-600' : 'text-slate-400 hover:bg-slate-50'}`}
            >
                支出明細
            </button>
            <button 
                 onClick={() => setActiveSubTab('settle')}
                 className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeSubTab === 'settle' ? 'bg-winter-100 text-winter-600' : 'text-slate-400 hover:bg-slate-50'}`}
            >
                結算 & 統計
            </button>
        </div>
      </div>

      {activeSubTab === 'list' ? (
        // --- LIST VIEW ---
        <div className="flex-1 overflow-y-auto px-4 pb-24 space-y-4 pt-4">
            <div className="flex justify-between items-center mb-2">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider">點擊項目可編輯</h3>
            <button onClick={openAddModal} className="text-winter-600 bg-winter-100 p-2 rounded-full hover:bg-winter-200 transition-colors">
                <Plus size={20} />
            </button>
            </div>

            {sortedDates.map(date => (
                <div key={date}>
                    <div className="text-xs font-bold text-slate-400 mb-2 mt-4 ml-1 flex items-center">
                        <Calendar size={12} className="mr-1"/> {date}
                    </div>
                    <div className="space-y-3">
                    {expensesByDate[date].map(expense => {
                    const payerMember = members.find(m => m.id === expense.payerId);
                    const icon = (CATEGORY_ICONS as any)[expense.category] || '💸';

                    return (
                        <div 
                           key={expense.id} 
                           onClick={() => openEditModal(expense)}
                           className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex justify-between items-center cursor-pointer hover:border-winter-200 transition-colors"
                        >
                        <div className="flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xl bg-slate-50 border border-slate-100`}>
                            {icon}
                            </div>
                            <div>
                            <div className="font-bold text-slate-800">{expense.description}</div>
                            <div className="text-xs text-slate-400 flex items-center gap-1">
                                <span className="font-medium text-slate-500">{payerMember?.name || 'Unknown'}</span> 付款
                                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                                <Users size={10} /> {expense.splitWithIds.length}
                            </div>
                            </div>
                        </div>
                        <div className="text-right">
                            <div className="font-bold text-slate-800">₩{expense.amountKRW.toLocaleString()}</div>
                            <div className="text-[10px] text-slate-400">NT$ {expense.amountTWD.toLocaleString()}</div>
                        </div>
                        </div>
                    );
                    })}
                    </div>
                </div>
            ))}
        </div>
      ) : (
        // --- SETTLEMENT VIEW ---
        <div className="flex-1 overflow-y-auto px-4 pb-24 pt-4 space-y-6">
            <div>
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3">分帳建議 (台幣)</h3>
                <div className="space-y-2">
                    {settlement.transactions.length === 0 ? (
                        <div className="text-center text-slate-400 py-4 bg-white rounded-2xl border border-slate-100">
                             目前收支平衡，無需轉帳 ✨
                        </div>
                    ) : (
                        settlement.transactions.map((t, idx) => {
                            const from = members.find(m => m.id === t.from);
                            const to = members.find(m => m.id === t.to);
                            return (
                                <div key={idx} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
                                    <div className="flex items-center gap-2">
                                        <img src={from?.avatar} className="w-8 h-8 rounded-full bg-slate-100"/>
                                        <ArrowRightLeft size={14} className="text-slate-300"/>
                                        <img src={to?.avatar} className="w-8 h-8 rounded-full bg-slate-100"/>
                                    </div>
                                    <div className="text-sm">
