                                        <div className="font-bold text-winter-600">NT$ {share.toLocaleString()}</div>
                                        {e.splitWithIds.length > 1 && (
                                            <div className="text-[9px] text-slate-400">總額 {e.amountTWD} / {e.splitWithIds.length}人</div>
                                        )}
                                    </div>
                                </div>
