            </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Tab, Member } from './types';
import { MEMBERS } from './constants';
import { ScheduleView } from './components/ScheduleView';
import { ExpenseView } from './components/ExpenseView';
import { PlanningView } from './components/PlanningView';
import { JournalView } from './components/JournalView';
import { Calendar, DollarSign, BookOpen, CheckSquare, Settings, X } from 'lucide-react';
import { db } from './services/firebase';
import { collection, onSnapshot, doc, updateDoc, setDoc, getDocs } from 'firebase/firestore';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.SCHEDULE);
  const [members, setMembers] = useState<Member[]>([]);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Sync Members from Firestore
  useEffect(() => {
    // 1. Listen for updates
    const unsubscribe = onSnapshot(collection(db, 'members'), (snapshot) => {
      const fetchedMembers: Member[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as Member));

      // Sort by ID to keep order consistent (m1, m2...)
      fetchedMembers.sort((a, b) => a.id.localeCompare(b.id));

      if (fetchedMembers.length > 0) {
        setMembers(fetchedMembers);
      } else {
        // 2. Seed if empty (First run)
        seedMembers();
      }
    });

    return () => unsubscribe();
  }, []);

  const seedMembers = async () => {
    for (const member of MEMBERS) {
      await setDoc(doc(db, 'members', member.id), member);
    }
  };

  const handleUpdateMemberName = async (id: string, newName: string) => {
    await updateDoc(doc(db, 'members', id), { name: newName });
  };

  const renderContent = () => {
    switch (activeTab) {
      case Tab.SCHEDULE:
        // Pass members to ScheduleView for the pre-trip checklist
        return <ScheduleView members={members} />;
      case Tab.EXPENSE:
        return <ExpenseView members={members} />;
      case Tab.PLANNING:
        return <PlanningView members={members} />;
      case Tab.JOURNAL:
        return <JournalView members={members} />;
      default:
        return <ScheduleView members={members} />;
    }
  };

  return (
    <div className="h-screen w-full max-w-md mx-auto bg-paper flex flex-col relative shadow-2xl overflow-hidden">
      {/* Header */}
      <header className="px-6 py-5 flex justify-between items-center bg-paper z-10 border-b border-slate-100">
        <div>
           <h1 className="text-2xl font-bold text-slate-800 tracking-tight">韓國之旅 🇰🇷</h1>
           <p className="text-xs text-slate-500 font-medium">2026/01/30 - 02/05</p>
        </div>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="w-10 h-10 rounded-full bg-white shadow-soft flex items-center justify-center border-2 border-slate-100 hover:bg-slate-50 transition-colors"
        >
           <Settings size={20} className="text-slate-400" />
        </button>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden relative">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="bg-white border-t border-slate-100 pb-safe pt-2 px-2 flex justify-around items-center z-50">
        <NavButton 
          active={activeTab === Tab.SCHEDULE} 
          onClick={() => setActiveTab(Tab.SCHEDULE)} 
          icon={Calendar} 
          label="行程" 
        />
        <NavButton 
          active={activeTab === Tab.EXPENSE} 
          onClick={() => setActiveTab(Tab.EXPENSE)} 
          icon={DollarSign} 
          label="記帳" 
        />
        <NavButton 
          active={activeTab === Tab.PLANNING} 
          onClick={() => setActiveTab(Tab.PLANNING)} 
          icon={CheckSquare} 
          label="清單" 
        />
        <NavButton 
          active={activeTab === Tab.JOURNAL} 
          onClick={() => setActiveTab(Tab.JOURNAL)} 
          icon={BookOpen} 
          label="日誌" 
        />
      </nav>

      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="absolute inset-0 bg-black/20 backdrop-blur-sm z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-6 w-full max-w-sm shadow-xl border-2 border-slate-100">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-slate-800">旅伴設定</h2>
              <button onClick={() => setIsSettingsOpen(false)}><X className="text-slate-400" /></button>
            </div>
            <div className="space-y-4">
              {members.map(member => (
                <div key={member.id} className="flex items-center gap-3">
                  <div className={`w-10 h-10 rounded-full flex-shrink-0 border-2 border-slate-100 overflow-hidden ${member.color}`}>
                    <img src={member.avatar} alt="avatar" className="w-full h-full object-cover transform scale-110" />
                  </div>
                  <input 
                    type="text" 
                    value={member.name}
                    onChange={(e) => handleUpdateMemberName(member.id, e.target.value)}
                    className="flex-1 p-2 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold text-slate-700 focus:border-winter-400 outline-none"
                  />
                </div>
              ))}
            </div>
            <button 
              onClick={() => setIsSettingsOpen(false)}
              className="w-full mt-6 py-3 bg-winter-500 text-white font-bold rounded-xl shadow-soft-sm active:scale-95 transition-transform"
            >
              完成
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.FC<{ size?: number; className?: string; strokeWidth?: number }>;
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon: Icon, label }) => (
  <button
    onClick={onClick}
    className="flex flex-col items-center justify-center w-16 py-1 group"
  >
    <div className={`mb-1 transition-colors duration-200 ${active ? 'text-winter-500' : 'text-slate-300 group-hover:text-slate-400'}`}>
      <Icon size={24} strokeWidth={active ? 2.5 : 2} />
    </div>
    <span className={`text-[10px] font-bold transition-colors duration-200 ${active ? 'text-winter-500' : 'text-slate-300'}`}>
      {label}
    </span>
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { ScheduleEvent, EventCategory, PreTripTask, Member } from '../types';
import { CATEGORY_COLORS, CATEGORY_ICONS } from '../constants';
import { MapPin, Info, Plus, X, Check, Trash2 } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, query, onSnapshot, addDoc, deleteDoc, updateDoc, doc, arrayUnion, arrayRemove } from 'firebase/firestore';

interface ScheduleViewProps {
  members: Member[];
}

export const ScheduleView: React.FC<ScheduleViewProps> = ({ members }) => {
  // Dates including "Pre-trip"
  const dates = [
    { display: '行前', val: 'PRE_TRIP' },
    { display: '1/30 (五)', val: '2026-01-30' },
    { display: '1/31 (六)', val: '2026-01-31' },
    { display: '2/1 (日)', val: '2026-02-01' },
    { display: '2/2 (一)', val: '2026-02-02' },
    { display: '2/3 (二)', val: '2026-02-03' },
    { display: '2/4 (三)', val: '2026-02-04' },
    { display: '2/5 (四)', val: '2026-02-05' },
  ];

  const [selectedDate, setSelectedDate] = useState(dates[1].val); // Default to first actual day
  const [events, setEvents] = useState<ScheduleEvent[]>([]);
  const [preTripTasks, setPreTripTasks] = useState<PreTripTask[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Form State
  const [newLocation, setNewLocation] = useState('');
  const [newCategory, setNewCategory] = useState<EventCategory>(EventCategory.SIGHTSEEING);
  const [newNotes, setNewNotes] = useState('');

  // Pre-trip Task Form
  const [newTaskTitle, setNewTaskTitle] = useState('');

  // Firestore Sync - Events
  useEffect(() => {
    const q = query(collection(db, 'events'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedEvents: ScheduleEvent[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as ScheduleEvent));
      setEvents(fetchedEvents);
    });
    return () => unsubscribe();
  }, []);

  // Firestore Sync - Pre-trip Tasks
  useEffect(() => {
    const q = query(collection(db, 'pretrip_tasks'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedTasks: PreTripTask[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as PreTripTask));
      setPreTripTasks(fetchedTasks);
    });
    return () => unsubscribe();
  }, []);

  // --- Pre-trip Handlers ---
  const handleAddPreTripTask = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newTaskTitle.trim()) return;
      await addDoc(collection(db, 'pretrip_tasks'), {
          title: newTaskTitle,
          completedBy: [],
          createdAt: new Date().toISOString()
      });
      setNewTaskTitle('');
  };

  const deletePreTripTask = async (id: string) => {
      if(window.confirm("刪除此行前項目？")) {
          await deleteDoc(doc(db, 'pretrip_tasks', id));
      }
  }

  const toggleTaskCompletion = async (taskId: string, memberId: string, isCompleted: boolean) => {
      const taskRef = doc(db, 'pretrip_tasks', taskId);
      if (isCompleted) {
          await updateDoc(taskRef, { completedBy: arrayRemove(memberId) });
      } else {
          await updateDoc(taskRef, { completedBy: arrayUnion(memberId) });
      }
  };

  // --- Schedule Handlers ---
  const openAddModal = () => {
    setEditingId(null);
    setNewLocation('');
    setNewCategory(EventCategory.SIGHTSEEING);
    setNewNotes('');
    setIsModalOpen(true);
  };

  const openEditModal = (event: ScheduleEvent) => {
    setEditingId(event.id);
    setNewLocation(event.location);
    // Ensure the category is valid or default to Sightseeing
    setNewCategory(event.category as EventCategory || EventCategory.SIGHTSEEING);
    setNewNotes(event.notes || '');
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newLocation) return;

    try {
      if (editingId) {
        // Update existing
        await updateDoc(doc(db, 'events', editingId), {
          location: newLocation,
          category: newCategory,
          notes: newNotes,
        });
      } else {
        // Add new
        await addDoc(collection(db, 'events'), {
          date: selectedDate,
          time: '', 
          title: '', 
          location: newLocation,
          category: newCategory,
          notes: newNotes,
          createdAt: new Date().toISOString()
        });
      }
      setIsModalOpen(false);
      setEditingId(null);
      setNewLocation('');
      setNewNotes('');
    } catch (error) {
      console.error("Error saving event: ", error);
    }
  };

  const handleDeleteEvent = async () => {
    if (!editingId) return;
    if(window.confirm("確定要刪除這個行程嗎？")) {
      await deleteDoc(doc(db, 'events', editingId));
      setIsModalOpen(false);
    }
  }

  const filteredEvents = events
    .filter(e => e.date === selectedDate)
    .sort((a, b) => (a.createdAt || '').localeCompare(b.createdAt || '')); 

  const sortedTasks = preTripTasks.sort((a, b) => (a.createdAt || '').localeCompare(b.createdAt || ''));

  return (
    <div className="h-full flex flex-col relative">
      {/* Date Picker */}
      <div className="flex overflow-x-auto no-scrollbar gap-2 p-4 pb-2 sticky top-0 bg-paper/95 backdrop-blur z-10">
        {dates.map((d) => (
          <button
            key={d.val}
            onClick={() => setSelectedDate(d.val)}
            className={`flex-shrink-0 flex flex-col items-center justify-center w-16 h-16 rounded-2xl border-2 transition-all active:scale-95 duration-200 ${
              selectedDate === d.val
                ? 'bg-winter-200 border-winter-400 shadow-soft text-winter-900'
                : 'bg-white border-slate-200 text-slate-400'
            }`}
          >
            <span className="text-xs font-bold whitespace-nowrap">{d.display.includes(' ') ? d.display.split(' ')[0] : d.display}</span>
            <span className="text-[10px]">{d.display.includes(' ') ? d.display.split(' ')[1] : ''}</span>
          </button>
        ))}
      </div>

      {/* Main Content */}
      <div className="flex-1 overflow-y-auto p-4 pb-24">

        {/* === PRE-TRIP CHECKLIST MODE === */}
        {selectedDate === 'PRE_TRIP' ? (
             <div className="space-y-4">
                 <div className="bg-white p-4 rounded-3xl border border-slate-100 shadow-soft-sm">
                     <h3 className="text-lg font-bold text-slate-800 mb-3">行前準備清單</h3>
                     <form onSubmit={handleAddPreTripTask} className="relative mb-6">
                        <input 
                           type="text" 
                           placeholder="新增準備事項 (例如: 買網卡...)" 
                           value={newTaskTitle}
                           onChange={e => setNewTaskTitle(e.target.value)}
                           className="w-full pl-4 pr-10 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:border-winter-400 outline-none text-sm"
                        />
                        <button type="submit" className="absolute right-2 top-2 p-1 bg-winter-500 text-white rounded-lg hover:bg-winter-600">
                           <Plus size={20} />
                        </button>
                     </form>

                     <div className="space-y-4">
                        {sortedTasks.map(task => (
                            <div key={task.id} className="bg-white rounded-xl border border-slate-100 p-3 shadow-sm">
                                <div className="flex justify-between items-start mb-2">
                                    <span className="font-bold text-slate-700">{task.title}</span>
                                    <button onClick={() => deletePreTripTask(task.id)} className="text-slate-300 hover:text-rose-400">
                                        <X size={14} />
                                    </button>
                                </div>
                                <div className="flex gap-3 mt-2 overflow-x-auto no-scrollbar">
                                    {members.map(member => {
                                        const isDone = task.completedBy.includes(member.id);
                                        return (
                                            <button 
                                                key={member.id}
                                                onClick={() => toggleTaskCompletion(task.id, member.id, isDone)}
                                                className={`flex flex-col items-center gap-1 transition-all active:scale-90`}
                                            >
                                                <div className={`w-8 h-8 rounded-full border-2 overflow-hidden relative ${isDone ? 'border-winter-400' : 'border-slate-200 grayscale opacity-60'}`}>
                                                    <img src={member.avatar} className="w-full h-full object-cover transform scale-110"/>
                                                    {isDone && (
                                                        <div className="absolute -bottom-1 -right-1 bg-winter-500 rounded-full p-0.5 border border-white z-10">
                                                            <Check size={8} className="text-white"/>
                                                        </div>
                                                    )}
                                                </div>
                                                <span className={`text-[9px] font-bold ${isDone ? 'text-winter-600' : 'text-slate-400'}`}>
                                                    {member.name}
                                                </span>
                                            </button>
                                        )
                                    })}
                                </div>
                            </div>
                        ))}
                        {sortedTasks.length === 0 && (
                            <p className="text-center text-slate-400 text-sm py-4">還沒有項目，新增一個吧！</p>
                        )}
                     </div>
                 </div>
             </div>
        ) : (
        /* === TIMELINE MODE === */
        <>
            {filteredEvents.length === 0 ? (
            <div className="text-center text-slate-400 mt-10">
                <p>這天還沒有安排行程</p>
                <button onClick={openAddModal} className="mt-4 text-winter-600 font-bold hover:underline">新增一個？</button>
            </div>
            ) : (
            filteredEvents.map((event, index) => {
                const colorClass = CATEGORY_COLORS[event.category] || 'bg-slate-100 text-slate-700 border-slate-200';
                const borderColor = colorClass.split(' ')[2] || 'border-slate-200';
                const icon = CATEGORY_ICONS[event.category] || '📌';

                return (
                <div key={event.id} className="relative pl-6 group">
                    {/* Timeline Line */}
                    {index !== filteredEvents.length - 1 && (
                    <div className="absolute left-[11px] top-8 bottom-[-16px] w-[2px] bg-slate-200"></div>
                    )}
                    {/* Dot */}
                    <div className={`absolute left-[-8px] top-3 w-10 h-10 rounded-full border-4 border-white shadow-sm z-10 flex items-center justify-center text-lg bg-white`}>
                    {icon}
                    </div>

                    {/* Card */}
                    <div 
                    onClick={() => openEditModal(event)}
                    className={`relative p-4 ml-2 rounded-2xl border-2 shadow-soft-sm bg-white hover:shadow-soft transition-all active:scale-[0.98] cursor-pointer ${borderColor}`}
                    >
                    <div className="flex justify-between items-start mb-1">
                        <div className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wider mb-2 ${colorClass}`}>
                        {event.category}
                        </div>
                    </div>

                    <h3 className="text-lg font-bold text-slate-800 mb-1 leading-tight flex items-center">
                        <MapPin size={16} className="mr-1 text-winter-500 inline flex-shrink-0" />
                        {event.location}
                    </h3>

                    {event.notes && (
                        <div className="mt-2 text-xs text-slate-500 bg-slate-50 p-2 rounded-lg border border-slate-100 flex items-start">
                        <Info size={12} className="mr-1 mt-0.5 flex-shrink-0" />
                        {event.notes}
                        </div>
                    )}
                    </div>
                </div>
                );
            })
            )}

            {/* Floating Add Button for Schedule */}
            <button 
                onClick={openAddModal}
                className="absolute bottom-24 right-4 w-14 h-14 bg-winter-500 text-white rounded-full shadow-soft flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-20"
            >
            <Plus size={28} />
            </button>
        </>
        )}
      </div>

      {/* Add/Edit Modal (Schedule Only) */}
      {isModalOpen && selectedDate !== 'PRE_TRIP' && (
        <div className="absolute inset-0 z-50 bg-black/20 backdrop-blur-sm flex items-end sm:items-center justify-center p-4">
           <div className="bg-white w-full rounded-3xl p-6 shadow-2xl border-2 border-slate-100 relative animate-in slide-in-from-bottom-10 fade-in">
              <button onClick={() => setIsModalOpen(false)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
              <h2 className="text-xl font-bold text-slate-800 mb-6">{editingId ? '編輯行程' : '新增行程'}</h2>
              <form onSubmit={handleSubmit} className="space-y-4">
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">地點 / 事項</label>
                    <input type="text" placeholder="例如：景福宮、弘大..." value={newLocation} onChange={e => setNewLocation(e.target.value)} className="w-full mt-1 p-3 bg-slate-50 rounded-xl border border-slate-200 focus:border-winter-400 outline-none" required />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">分類</label>
                    <div className="grid grid-cols-5 gap-1 mt-1">
                       {Object.values(EventCategory).map(cat => (
                          <button
                            key={cat}
                            type="button"
                            onClick={() => setNewCategory(cat)}
                            className={`px-1 py-2 rounded-lg text-[10px] font-bold transition-all flex flex-col items-center gap-1 ${newCategory === cat ? CATEGORY_COLORS[cat] + ' ring-2 ring-offset-1 ring-slate-200' : 'bg-slate-50 text-slate-500 border border-slate-100'}`}
                          >
                             <span className="text-lg">{CATEGORY_ICONS[cat]}</span>
                             {cat}
                          </button>
                       ))}
                    </div>
                 </div>
                 <div>
                    <label className="text-xs font-bold text-slate-400 uppercase">備註</label>
                    <textarea placeholder="詳細資訊..." value={newNotes} onChange={e => setNewNotes(e.target.value)} className="w-full mt-1 p-3 bg-slate-50 rounded-xl border border-slate-200 h-20 focus:border-winter-400 outline-none" />
                 </div>
                 <div className="flex gap-3 mt-6">
                     {editingId && (
                         <button type="button" onClick={handleDeleteEvent} className="px-4 py-3 bg-rose-50 text-rose-500 font-bold rounded-xl border border-rose-100">
                             <Trash2 size={20} />
                         </button>
                     )}
                     <button type="submit" className="flex-1 py-3 bg-winter-500 text-white font-bold rounded-xl shadow-soft-sm active:scale-95 transition-transform">
                        {editingId ? '儲存變更' : '加入行程'}
                     </button>
                 </div>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Expense, Member, EventCategory } from '../types';
import { EXCHANGE_RATE, CATEGORY_ICONS } from '../constants';
import { Plus, Users, Calendar, ArrowRightLeft, Calculator, X, ChevronRight, Trash2 } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, query, onSnapshot, addDoc, updateDoc, deleteDoc, doc, orderBy } from 'firebase/firestore';

interface ExpenseViewProps {
  members: Member[];
}

export const ExpenseView: React.FC<ExpenseViewProps> = ({ members }) => {
  const [activeSubTab, setActiveSubTab] = useState<'list' | 'settle'>('list');
  const [expenses, setExpenses] = useState<Expense[]>([]);

  // Modal States
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [detailMemberId, setDetailMemberId] = useState<string | null>(null); // For personal spending details

  // Form State
  const [amountInput, setAmountInput] = useState('');
  const [inputCurrency, setInputCurrency] = useState<'KRW' | 'TWD'>('KRW');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState<string>(EventCategory.FOOD);
  const [payer, setPayer] = useState(members[0]?.id || '');
  const [selectedSplits, setSelectedSplits] = useState<string[]>([]);
  const [newDate, setNewDate] = useState(new Date().toISOString().split('T')[0]);

  // Initialize splits
  useEffect(() => {
    if (members.length > 0 && selectedSplits.length === 0) {
        setSelectedSplits(members.map(m => m.id));
        if (!payer) setPayer(members[0].id);
    }
  }, [members]);

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'expenses'), orderBy('date', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedExpenses: Expense[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as Expense));
      setExpenses(fetchedExpenses);
    });
    return () => unsubscribe();
  }, []);

  const openAddModal = () => {
    setEditingId(null);
    setAmountInput('');
    setInputCurrency('KRW');
    setDescription('');
    setCategory(EventCategory.FOOD);
    setNewDate(new Date().toISOString().split('T')[0]);
    // Reset splits to all
    setSelectedSplits(members.map(m => m.id));
    setPayer(members[0].id);
    setIsModalOpen(true);
  };

  const openEditModal = (exp: Expense) => {
    setEditingId(exp.id);
    // Use stored currency preference or default to KRW if not present
    const currency = exp.currency || 'KRW';
    setInputCurrency(currency);
    setAmountInput(currency === 'KRW' ? exp.amountKRW.toString() : exp.amountTWD.toString());
    setDescription(exp.description);
    setCategory(exp.category);
    setPayer(exp.payerId);
    setSelectedSplits(exp.splitWithIds);
    setNewDate(exp.date);
    setIsModalOpen(true);
  };

  const handleSave = async () => {
    if (!amountInput || !description) return;

    let amountKRW = 0;
    let amountTWD = 0;
    const inputVal = parseInt(amountInput);

    if (inputCurrency === 'KRW') {
        amountKRW = inputVal;
        amountTWD = Math.round(inputVal * EXCHANGE_RATE);
    } else {
        amountTWD = inputVal;
        amountKRW = Math.round(inputVal / EXCHANGE_RATE);
    }

    const expenseData = {
        amountKRW,
        amountTWD,
        currency: inputCurrency,
        category,
        description,
        payerId: payer,
        splitWithIds: selectedSplits,
        date: newDate,
        timestamp: new Date().toISOString()
    };

    try {
      if (editingId) {
        await updateDoc(doc(db, 'expenses', editingId), expenseData);
      } else {
        await addDoc(collection(db, 'expenses'), expenseData);
      }
      setIsModalOpen(false);
    } catch (error) {
      console.error("Error saving expense: ", error);
    }
  };

  const handleDelete = async () => {
      if (!editingId) return;
      if (window.confirm("確定刪除這筆款項？")) {
          await deleteDoc(doc(db, 'expenses', editingId));
          setIsModalOpen(false);
      }
  }

  const toggleSplit = (id: string) => {
    if (selectedSplits.includes(id)) {
      if (selectedSplits.length > 1) { // Prevent empty split
        setSelectedSplits(selectedSplits.filter(s => s !== id));
      }
    } else {
      setSelectedSplits([...selectedSplits, id]);
    }
  };

  // --- SETTLEMENT LOGIC ---
  const calculateSettlement = () => {
    // 1. Calculate Net Balance for each person
    const balances: Record<string, number> = {};
    const paidTotals: Record<string, number> = {};
    const shareTotals: Record<string, number> = {};

    members.forEach(m => {
        balances[m.id] = 0;
        paidTotals[m.id] = 0;
        shareTotals[m.id] = 0;
    });

    expenses.forEach(exp => {
        const amount = exp.amountTWD; 

        // Credit the payer
        balances[exp.payerId] += amount;
        paidTotals[exp.payerId] += amount;

        // Debit the consumers
        const splitCount = exp.splitWithIds.length;
        if (splitCount > 0) {
            const share = amount / splitCount;
            exp.splitWithIds.forEach(id => {
                if (balances[id] !== undefined) {
                    balances[id] -= share;
                    shareTotals[id] += share;
                }
            });
        }
    });

    // 2. Simplification Algorithm (Who pays whom)
    const debtors: {id: string, amount: number}[] = [];
    const creditors: {id: string, amount: number}[] = [];

    Object.entries(balances).forEach(([id, amount]) => {
        if (amount < -1) debtors.push({ id, amount }); // Owe money
        else if (amount > 1) creditors.push({ id, amount }); // Are owed money
    });

    debtors.sort((a, b) => a.amount - b.amount); // Most negative first
    creditors.sort((a, b) => b.amount - a.amount); // Most positive first

    const transactions: {from: string, to: string, amount: number}[] = [];

    let i = 0; // debtor index
    let j = 0; // creditor index

    while (i < debtors.length && j < creditors.length) {
        const debtor = debtors[i];
        const creditor = creditors[j];

        // The amount to settle is the minimum of what debtor owes and creditor is owed
        const amount = Math.min(Math.abs(debtor.amount), creditor.amount);

        transactions.push({ from: debtor.id, to: creditor.id, amount: Math.round(amount) });

        debtor.amount += amount;
        creditor.amount -= amount;

        if (Math.abs(debtor.amount) < 1) i++;
        if (creditor.amount < 1) j++;
    }

    return { transactions, paidTotals, shareTotals };
  };

  const settlement = calculateSettlement();

  // Group expenses by date for List View
  const expensesByDate: Record<string, Expense[]> = {};
  expenses.forEach(exp => {
      if (!expensesByDate[exp.date]) {
          expensesByDate[exp.date] = [];
      }
      expensesByDate[exp.date].push(exp);
  });
  const sortedDates = Object.keys(expensesByDate).sort((a, b) => b.localeCompare(a));

  return (
    <div className="h-full flex flex-col">
      {/* Sub Tabs */}
      <div className="px-4 pt-4">
        <div className="bg-white p-1 rounded-xl border border-slate-100 flex shadow-sm">
            <button 
                onClick={() => setActiveSubTab('list')}
                className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeSubTab === 'list' ? 'bg-winter-100 text-winter-600' : 'text-slate-400 hover:bg-slate-50'}`}
            >
                支出明細
            </button>
            <button 
                 onClick={() => setActiveSubTab('settle')}
                 className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${activeSubTab === 'settle' ? 'bg-winter-100 text-winter-600' : 'text-slate-400 hover:bg-slate-50'}`}
            >
                結算 & 統計
            </button>
        </div>
      </div>

      {activeSubTab === 'list' ? (
        // --- LIST VIEW ---
        <div className="flex-1 overflow-y-auto px-4 pb-24 space-y-4 pt-4">
            <div className="flex justify-between items-center mb-2">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider">點擊項目可編輯</h3>
            <button onClick={openAddModal} className="text-winter-600 bg-winter-100 p-2 rounded-full hover:bg-winter-200 transition-colors">
                <Plus size={20} />
            </button>
            </div>

            {sortedDates.map(date => (
                <div key={date}>
                    <div className="text-xs font-bold text-slate-400 mb-2 mt-4 ml-1 flex items-center">
                        <Calendar size={12} className="mr-1"/> {date}
                    </div>
                    <div className="space-y-3">
                    {expensesByDate[date].map(expense => {
                    const payerMember = members.find(m => m.id === expense.payerId);
                    const icon = (CATEGORY_ICONS as any)[expense.category] || '💸';

                    return (
                        <div 
                           key={expense.id} 
                           onClick={() => openEditModal(expense)}
                           className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex justify-between items-center cursor-pointer hover:border-winter-200 transition-colors"
                        >
                        <div className="flex items-center gap-3">
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xl bg-slate-50 border border-slate-100`}>
                            {icon}
                            </div>
                            <div>
                            <div className="font-bold text-slate-800">{expense.description}</div>
                            <div className="text-xs text-slate-400 flex items-center gap-1">
                                <span className="font-medium text-slate-500">{payerMember?.name || 'Unknown'}</span> 付款
                                <span className="w-1 h-1 bg-slate-300 rounded-full"></span>
                                <div className="flex items-center">
                                  {expense.splitWithIds.slice(0, 5).map(id => {
                                      const m = members.find(mem => mem.id === id);
                                      if(!m) return null;
                                      return (
                                          <img key={id} src={m.avatar} className="w-4 h-4 rounded-full border border-white -ml-1 first:ml-0 bg-slate-200" alt=""/>
                                      )
                                  })}
                                  {expense.splitWithIds.length > 5 && <span className="text-[9px] ml-1">+{expense.splitWithIds.length - 5}</span>}
                                </div>
                            </div>
                            </div>
                        </div>
                        <div className="text-right">
                            <div className="font-bold text-slate-800">₩{expense.amountKRW.toLocaleString()}</div>
                            <div className="text-[10px] text-slate-400">NT$ {expense.amountTWD.toLocaleString()}</div>
                        </div>
                        </div>
                    );
                    })}
                    </div>
                </div>
            ))}
        </div>
      ) : (
        // --- SETTLEMENT VIEW ---
        <div className="flex-1 overflow-y-auto px-4 pb-24 pt-4 space-y-6">
            <div>
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3">分帳建議 (台幣)</h3>
                <div className="space-y-2">
                    {settlement.transactions.length === 0 ? (
                        <div className="text-center text-slate-400 py-4 bg-white rounded-2xl border border-slate-100">
                             目前收支平衡，無需轉帳 ✨
                        </div>
                    ) : (
                        settlement.transactions.map((t, idx) => {
                            const from = members.find(m => m.id === t.from);
                            const to = members.find(m => m.id === t.to);
                            return (
                                <div key={idx} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between">
                                    <div className="flex items-center gap-2">
                                        <img src={from?.avatar} className="w-8 h-8 rounded-full bg-slate-100"/>
                                        <ArrowRightLeft size={14} className="text-slate-300"/>
                                        <img src={to?.avatar} className="w-8 h-8 rounded-full bg-slate-100"/>
                                    </div>
                                    <div className="text-sm">
                                        <span className="font-bold text-slate-700">{from?.name}</span>
                                        <span className="text-slate-400 mx-1">給</span>
                                        <span className="font-bold text-slate-700">{to?.name}</span>
                                        <span className="font-bold text-winter-600 ml-2">NT$ {t.amount.toLocaleString()}</span>
                                    </div>
                                </div>
                            )
                        })
                    )}
                </div>
            </div>

            <div>
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-3">旅程總花費 (點擊查看明細)</h3>
                <div className="grid grid-cols-1 gap-3">
                    {members.map(m => (
                        <div 
                            key={m.id} 
                            onClick={() => setDetailMemberId(m.id)}
                            className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between cursor-pointer hover:border-winter-200 hover:bg-winter-50 transition-colors group"
                        >
                            <div className="flex items-center gap-3">
                                <img src={m.avatar} className="w-10 h-10 rounded-full bg-slate-50 object-cover"/>
                                <div>
                                    <div className="font-bold text-slate-700">{m.name}</div>
                                    <div className="text-[10px] text-slate-400">實際消費</div>
                                </div>
                            </div>
                            <div className="flex items-center gap-2">
                                <div className="text-right">
                                    <div className="font-bold text-winter-600 text-lg">NT$ {Math.round(settlement.shareTotals[m.id]).toLocaleString()}</div>
                                </div>
                                <ChevronRight className="text-slate-300 group-hover:text-winter-400" size={16}/>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
      )}

      {/* Expense Form Modal - Compacted */}
      {isModalOpen && (
        <div className="absolute inset-0 z-50 bg-black/20 backdrop-blur-sm flex items-end sm:items-center justify-center p-4">
            <div className="bg-white w-full rounded-3xl p-5 shadow-2xl border-2 border-slate-100 relative animate-in slide-in-from-bottom-10 fade-in">
                <button onClick={() => setIsModalOpen(false)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600">
                    <X size={24} />
                </button>
                <div className="mb-4">
                    <h2 className="text-lg font-bold text-slate-800">{editingId ? '編輯款項' : '新增記帳'}</h2>
                </div>

                <div className="space-y-3">
                    {/* Amount & Currency Row */}
                    <div className="flex gap-2 items-end">
                        <div className="flex-1">
                            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">金額</label>
                            <input
                                type="number"
                                inputMode="numeric"
                                value={amountInput}
                                onChange={(e) => setAmountInput(e.target.value)}
                                className="w-full text-2xl font-bold text-slate-800 border-b-2 border-slate-200 focus:border-winter-400 outline-none py-1 bg-transparent"
                                placeholder="0"
                            />
                        </div>
                        <div className="flex bg-slate-100 rounded-lg p-1 mb-1">
                             <button onClick={() => setInputCurrency('KRW')} className={`px-2 py-1 rounded-md text-[10px] font-bold transition-all ${inputCurrency === 'KRW' ? 'bg-white shadow-sm text-slate-800' : 'text-slate-400'}`}>KRW</button>
                             <button onClick={() => setInputCurrency('TWD')} className={`px-2 py-1 rounded-md text-[10px] font-bold transition-all ${inputCurrency === 'TWD' ? 'bg-white shadow-sm text-slate-800' : 'text-slate-400'}`}>TWD</button>
                        </div>
                    </div>

                    {/* Date & Desc Row */}
                    <div className="flex gap-2">
                        <div className="w-1/3">
                            <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">日期</label>
                            <input type="date" value={newDate} onChange={(e) => setNewDate(e.target.value)} className="w-full p-2 bg-slate-50 rounded-lg border border-slate-200 text-xs" />
                        </div>
                        <div className="flex-1">
                             <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">項目</label>
                             <input type="text" value={description} onChange={(e) => setDescription(e.target.value)} className="w-full p-2 bg-slate-50 rounded-lg border border-slate-200 text-xs" placeholder="例如：晚餐..." />
                        </div>
                    </div>

                    {/* Category Row */}
                    <div>
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">分類</label>
                        <div className="relative">
                            <select 
                                value={category}
                                onChange={(e) => setCategory(e.target.value)}
                                className="w-full p-2 bg-slate-50 rounded-lg border border-slate-200 appearance-none font-bold text-slate-700 text-xs"
                            >
                                {Object.values(EventCategory).map(cat => (
                                    <option key={cat} value={cat}>
                                        {CATEGORY_ICONS[cat]} {cat}
                                    </option>
                                ))}
                            </select>
                        </div>
                    </div>

                    {/* Payer Row - Compact */}
                    <div>
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">付款人</label>
                        <div className="grid grid-cols-5 gap-1">
                            {members.map(m => (
                                <button
                                    key={m.id}
                                    onClick={() => setPayer(m.id)}
                                    className={`flex flex-col items-center justify-center p-1 rounded-lg border-2 transition-all ${payer === m.id ? 'bg-slate-800 text-white border-slate-800 shadow-md' : 'bg-white border-slate-200 text-slate-600'}`}
                                >
                                    <div className="w-6 h-6 rounded-full overflow-hidden mb-0.5">
                                        <img src={m.avatar} alt={m.name} className="w-full h-full object-cover" />
                                    </div>
                                    <span className="text-[9px] font-bold truncate w-full text-center">{m.name}</span>
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Split Row - Compact */}
                    <div>
                        <label className="block text-[10px] font-bold text-slate-400 uppercase mb-1">分攤人 ({selectedSplits.length})</label>
                        <div className="grid grid-cols-5 gap-1">
                            {members.map(m => (
                                <button
                                    key={m.id}
                                    onClick={() => toggleSplit(m.id)}
                                    className={`flex flex-col items-center justify-center p-1 rounded-lg border-2 transition-all ${selectedSplits.includes(m.id) ? `border-winter-400 bg-winter-50` : 'border-transparent opacity-50 grayscale'}`}
                                >
                                    <div className="w-6 h-6 rounded-full overflow-hidden mb-0.5">
                                         <img src={m.avatar} alt={m.name} className="w-full h-full object-cover" />
                                    </div>
                                    <span className="text-[9px] font-bold text-slate-600 truncate w-full text-center">{m.name}</span>
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="flex gap-3 mt-5">
                    {editingId && (
                         <button type="button" onClick={handleDelete} className="px-3 py-3 bg-rose-50 text-rose-500 font-bold rounded-xl border border-rose-100">
                             <Trash2 size={20} />
                         </button>
                    )}
                    <button onClick={handleSave} className="flex-1 py-3 bg-winter-500 text-white font-bold rounded-xl shadow-soft-sm active:scale-95 transition-transform">
                        {editingId ? '儲存' : '新增'}
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Spending Details Modal */}
      {detailMemberId && (
          <div className="absolute inset-0 z-50 bg-black/20 backdrop-blur-sm flex items-end sm:items-center justify-center p-4">
            <div className="bg-white w-full max-h-[80vh] overflow-hidden flex flex-col rounded-3xl p-6 shadow-2xl border-2 border-slate-100 relative animate-in slide-in-from-bottom-10 fade-in">
                <button onClick={() => setDetailMemberId(null)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 z-10">
                    <X size={24} />
                </button>

                <h2 className="text-xl font-bold text-slate-800 mb-1 flex items-center gap-2">
                    <div className="w-8 h-8 rounded-full overflow-hidden bg-slate-100">
                        <img src={members.find(m => m.id === detailMemberId)?.avatar} className="w-full h-full object-cover"/>
                    </div>
                    消費明細
                </h2>
                <div className="text-xs text-slate-400 mb-4 ml-10">
                    總花費: NT$ {Math.round(settlement.shareTotals[detailMemberId]).toLocaleString()}
                </div>

                <div className="flex-1 overflow-y-auto space-y-2 pr-1">
                    {expenses
                        .filter(e => e.splitWithIds.includes(detailMemberId))
                        .map(e => {
                            const share = Math.round(e.amountTWD / e.splitWithIds.length);
                            return (
                                <div key={e.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl border border-slate-100">
                                    <div className="flex-1 min-w-0 mr-4">
                                        <div className="text-sm font-bold text-slate-700 truncate">{e.description}</div>
                                        <div className="text-[10px] text-slate-400">{e.date} • {CATEGORY_ICONS[e.category]} {e.category}</div>
                                    </div>
                                    <div className="text-right whitespace-nowrap">
                                        <div className="font-bold text-winter-600">NT$ {share.toLocaleString()}</div>
                                        {e.splitWithIds.length > 1 && (
                                            <div className="text-[9px] text-slate-400">總額 {e.amountTWD} / {e.splitWithIds.length}人</div>
                                        )}
                                    </div>
                                </div>
                            )
                        })
                    }
                    {expenses.filter(e => e.splitWithIds.includes(detailMemberId)).length === 0 && (
                        <div className="text-center text-slate-400 py-10">尚無消費紀錄</div>
                    )}
                </div>
            </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { TodoItem, Member } from '../types';
import { Check, Plus, ShoppingBag, X } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, query, onSnapshot, addDoc, updateDoc, doc, deleteDoc } from 'firebase/firestore';

interface PlanningViewProps {
  members: Member[];
}

export const PlanningView: React.FC<PlanningViewProps> = ({ members }) => {
  // Only 'shopping' type is relevant now
  const activeTab = 'shopping';
  const [activeMemberId, setActiveMemberId] = useState<string>('');
  const [todos, setTodos] = useState<TodoItem[]>([]);
  const [newItemText, setNewItemText] = useState('');

  useEffect(() => {
    if (members.length > 0 && !activeMemberId) {
        setActiveMemberId(members[0].id);
    }
  }, [members]);

  const activeMember = members.find(m => m.id === activeMemberId);

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'todos'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedTodos: TodoItem[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as TodoItem));
      setTodos(fetchedTodos);
    });
    return () => unsubscribe();
  }, []);

  const filteredTodos = todos.filter(
    t => t.ownerId === activeMemberId && t.type === activeTab
  );

  const toggleTodo = async (id: string, currentStatus: boolean) => {
    const todoRef = doc(db, 'todos', id);
    await updateDoc(todoRef, {
      completed: !currentStatus
    });
  };

  const deleteTodo = async (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      if (window.confirm("Delete item?")) {
        await deleteDoc(doc(db, 'todos', id));
      }
  }

  const addItem = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemText.trim()) return;

    try {
      await addDoc(collection(db, 'todos'), {
        text: newItemText,
        completed: false,
        ownerId: activeMemberId,
        type: activeTab,
        createdAt: new Date().toISOString()
      });
      setNewItemText('');
    } catch (error) {
      console.error("Error adding todo: ", error);
    }
  };

  return (
    <div className="h-full flex flex-col">
      {/* Title */}
      <div className="px-6 pt-6 pb-2">
         <div className="flex items-center text-slate-800 gap-2">
             <ShoppingBag className="text-winter-500" />
             <h2 className="text-xl font-bold">購物清單</h2>
         </div>
      </div>

      {/* Member Selector - Added padding to prevent overflow clipping */}
      <div className="px-4 py-4">
         <div className="flex gap-2 overflow-x-visible no-scrollbar pb-2 px-2">
            {members.map(m => (
              <button
                key={m.id}
                onClick={() => setActiveMemberId(m.id)}
                className={`flex-shrink-0 relative transition-all duration-300 ${activeMemberId === m.id ? 'scale-110 z-10' : 'opacity-60 scale-90'}`}
              >
                <div className={`w-14 h-14 rounded-full p-1 border-2 ${activeMemberId === m.id ? 'border-winter-400 shadow-md' : 'border-transparent'}`}>
                  <div className="w-full h-full rounded-full overflow-hidden">
                    <img src={m.avatar} alt={m.name} className="w-full h-full object-cover transform scale-110" />
                  </div>
                </div>
                {activeMemberId === m.id && (
                   <span className="absolute -bottom-2 left-1/2 transform -translate-x-1/2 bg-winter-500 text-white text-[10px] px-2 py-0.5 rounded-full font-bold shadow-sm whitespace-nowrap">
                     {m.name}
                   </span>
                )}
              </button>
            ))}
         </div>
      </div>

      {/* Checkbox List */}
      <div className="flex-1 overflow-y-auto p-4 pb-24 space-y-3">
        <div className={`p-4 rounded-3xl min-h-[300px] border-2 border-slate-100 bg-white/80 shadow-inner-soft`}>
          <h3 className="text-lg font-bold text-slate-700 mb-4 flex items-center">
            <span className={`w-2 h-8 rounded-full mr-3 ${activeMember?.color}`}></span>
            {activeMember?.name} 想買的東西
          </h3>

          <form onSubmit={addItem} className="mb-4 relative">
             <input 
                type="text" 
                value={newItemText}
                onChange={(e) => setNewItemText(e.target.value)}
                placeholder="輸入商品名稱..." 
                className="w-full pl-4 pr-10 py-3 rounded-xl bg-paper border border-slate-200 focus:border-winter-400 outline-none"
             />
             <button type="submit" className="absolute right-2 top-2 p-1 bg-winter-500 text-white rounded-lg hover:bg-winter-600">
               <Plus size={20} />
             </button>
          </form>

          <div className="space-y-2">
            {filteredTodos.map(item => (
              <div 
                key={item.id} 
                onClick={() => toggleTodo(item.id, item.completed)}
                className={`flex items-center p-3 rounded-xl cursor-pointer transition-all active:scale-[0.98] group ${
                  item.completed ? 'bg-slate-50 opacity-60' : 'bg-white shadow-sm border border-slate-100'
                }`}
              >
                <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center mr-3 transition-colors ${
                  item.completed ? 'bg-winter-400 border-winter-400' : 'border-slate-300'
                }`}>
                  {item.completed && <Check size={14} className="text-white" />}
                </div>
                <span className={`text-sm font-medium flex-1 ${item.completed ? 'text-slate-400 line-through' : 'text-slate-700'}`}>
                  {item.text}
                </span>
                <button onClick={(e) => deleteTodo(item.id, e)} className="text-slate-300 hover:text-rose-400 opacity-0 group-hover:opacity-100 transition-opacity px-2">
                    <X size={14} />
                </button>
              </div>
            ))}
            {filteredTodos.length === 0 && (
               <div className="text-center text-slate-300 py-8 italic text-sm">
                  目前沒有項目
               </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { PenTool, Send, X, Pencil } from 'lucide-react';
import { db } from '../services/firebase';
import { collection, query, onSnapshot, addDoc, updateDoc, deleteDoc, doc, orderBy } from 'firebase/firestore';
import { JournalEntry, Member } from '../types';

interface JournalViewProps {
  members: Member[];
}

export const JournalView: React.FC<JournalViewProps> = ({ members }) => {
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [inputContent, setInputContent] = useState('');
  const [authorId, setAuthorId] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);

  // Set default author when members load
  useEffect(() => {
    if (members.length > 0 && !authorId) {
        setAuthorId(members[0].id);
    }
  }, [members]);

  // Firestore Sync
  useEffect(() => {
    const q = query(collection(db, 'journal'), orderBy('date', 'desc'));
    const unsubscribe = onSnapshot(q, (snapshot) => {
      const fetchedEntries: JournalEntry[] = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      } as JournalEntry));
      setEntries(fetchedEntries);
    });
    return () => unsubscribe();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputContent.trim()) return;

    try {
      if (editingId) {
          await updateDoc(doc(db, 'journal', editingId), {
              content: inputContent,
              authorId: authorId, // Can update author too
          });
          setEditingId(null);
      } else {
          await addDoc(collection(db, 'journal'), {
            content: inputContent,
            date: new Date().toISOString(),
            authorId: authorId,
          });
      }
      setInputContent('');
    } catch (error) {
      console.error("Error posting journal: ", error);
    }
  };

  const startEdit = (entry: JournalEntry) => {
      setEditingId(entry.id);
      setInputContent(entry.content);
      setAuthorId(entry.authorId);
      // Scroll to top to see input
      const container = document.querySelector('.journal-container');
      if (container) container.scrollTop = 0;
  }

  const cancelEdit = () => {
      setEditingId(null);
      setInputContent('');
  }

  const handleDelete = async (id: string) => {
      if (window.confirm("Delete this entry?")) {
          await deleteDoc(doc(db, 'journal', id));
          if (editingId === id) cancelEdit();
      }
  }

  return (
    <div className="h-full flex flex-col p-4 overflow-y-auto pb-24 journal-container">
       <div className="bg-white rounded-3xl p-6 shadow-soft mb-6 text-center border-2 border-slate-100">
          <div className="w-16 h-16 bg-winter-100 rounded-full flex items-center justify-center mx-auto mb-3 text-winter-600">
             <PenTool size={32} />
          </div>
          <h2 className="text-xl font-bold text-slate-800">旅途日記</h2>
          <p className="text-slate-400 text-sm">記錄當下的心情...</p>
       </div>

       {/* Author Selector */}
       <div className="flex gap-2 overflow-x-auto no-scrollbar mb-2 px-1">
          {members.map(m => (
             <button
                key={m.id}
                onClick={() => setAuthorId(m.id)}
                className={`flex-shrink-0 flex items-center gap-2 px-3 py-1.5 rounded-full border transition-all ${authorId === m.id ? 'bg-slate-800 text-white border-slate-800' : 'bg-white border-slate-200 text-slate-500 opacity-60'}`}
             >
                <div className="w-5 h-5 rounded-full overflow-hidden">
                    <img src={m.avatar} alt={m.name} className="w-full h-full object-cover transform scale-110" />
                </div>
                <span className="text-xs font-bold">{m.name}</span>
             </button>
          ))}
       </div>

       {/* Simple Input Area */}
       <form onSubmit={handleSubmit} className="mb-6 relative">
          <textarea
             value={inputContent}
             onChange={e => setInputContent(e.target.value)}
             placeholder="發生了什麼趣事？"
             className={`w-full p-4 pr-12 rounded-2xl border-2 focus:border-winter-300 outline-none resize-none shadow-sm text-sm min-h-[100px] transition-colors ${editingId ? 'border-winter-300 bg-winter-50' : 'border-slate-100'}`}
          />
          <button type="submit" className="absolute bottom-3 right-3 p-2 bg-winter-500 text-white rounded-xl shadow-md hover:bg-winter-600 transition-colors">
             <Send size={16} />
          </button>
          {editingId && (
              <button type="button" onClick={cancelEdit} className="absolute top-2 right-2 p-1 text-slate-400 hover:text-slate-600">
                  <X size={16} />
              </button>
          )}
       </form>

       <div className="space-y-4">
          {entries.map(entry => {
             const author = members.find(m => m.id === entry.authorId);
             const dateObj = new Date(entry.date);
             // Format: MM/DD HH:mm
             const dateStr = `${dateObj.getMonth()+1}/${dateObj.getDate()} ${dateObj.getHours().toString().padStart(2, '0')}:${dateObj.getMinutes().toString().padStart(2, '0')}`;

             return (
               <div key={entry.id} className={`bg-white p-4 rounded-tr-3xl rounded-bl-3xl rounded-br-3xl shadow-sm border group transition-all ${editingId === entry.id ? 'border-winter-300 ring-2 ring-winter-100' : 'border-slate-100'}`}>
                  <div className="flex items-center gap-2 mb-2">
                     <div className="w-6 h-6 rounded-full overflow-hidden">
                         <img src={author?.avatar} alt={author?.name} className="w-full h-full object-cover transform scale-110" />
                     </div>
                     <span className="text-xs font-bold text-slate-700">{author?.name}</span>
                     <div className="text-[10px] font-bold text-slate-400 ml-auto flex items-center gap-2">
                        {dateStr}
                        <button onClick={() => startEdit(entry)} className="opacity-0 group-hover:opacity-100 p-1 text-winter-500 hover:bg-winter-50 rounded"><Pencil size={12} /></button>
                        <button onClick={() => handleDelete(entry.id)} className="opacity-0 group-hover:opacity-100 p-1 text-rose-400 hover:bg-rose-50 rounded"><X size={12} /></button>
                     </div>
                  </div>
                  <p className="text-slate-600 leading-relaxed text-sm whitespace-pre-wrap">
                     {entry.content}
                  </p>
               </div>
             );
          })}

          {entries.length === 0 && (
             <div className="text-center text-slate-300 text-sm italic">
                還沒有日記，來寫第一篇吧！
             </div>
          )}
       </div>
    </div>
  );
};
